values
  ('214', '과일무스 테린', '후식', ' 딸기 100g(5개), 키위 100g(1개), 매실원액 15g(1큰술), 젤라틴 20g
, 망고 20g(1/5개), 우유 45g(3큰술)', '["딸기","키위","매실원액","젤라틴","망고","우유"]'::jsonb, ARRAY['60a7c3e6-e703-4fb0-b5d9-0119a5deab83','e748d9a5-9c62-4d33-918a-b1b8e9a1f00b','e1ee1919-9a32-462f-ae14-55c7a47ce0a0','e937397f-54e2-49df-997a-f393c58360be']::uuid[], '[{"step":1,"text":"망고와 우유를 섞어 믹서에 갈아 팬에 넣고 끓인다.","imageUrl":null},{"step":2,"text":"딸기와 키위는 0.5×0.5×0.5cm로 썰고 젤라틴은 녹여서 매실원액과 섞는다.","imageUrl":null},{"step":3,"text":"딸기, 키위를 젤라틴과 섞어서 틀에 넣어 굳히고 위에 망고소스를 뿌려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00214_2.png', 67.5, 9.7, 7.1, 0, 12.4),
  ('215', '가지볶음밥', '밥', ' 단호박(100g), 양파(30g), 석박지(35g), 파프리카(40g), 가지(90g)
두부(50g), 밥(180g), 세발나물(10g),다진 마늘(5g), 저염된장(12g), 후춧가루(0.3g), 들기름(4g)', '["단호박","양파","석박지","파프리카","가지","두부","밥","세발나물","다진 마늘","저염된장","후춧가루","들기름"]'::jsonb, ARRAY['98d652af-a6d6-440c-9653-e22fc5d47d88','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5e79d288-1400-4817-bd20-e5e6041821b1','3e12cf79-2cde-4309-9f7c-4eccce3fde28','4566cac5-9166-4c0d-906a-bfc7360f8f5b','ecb35816-34ae-4c4c-867a-e3f84db92755','fc6e31ce-388e-45cd-956b-b238b9134eb1','392236b1-82e9-4e38-bd12-6a53b80bf463','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','f5534afd-2a26-4493-8ec1-fd680dcb3bef']::uuid[], '[{"step":1,"text":"단호박은 삶아 으깬다.","imageUrl":null},{"step":2,"text":"양파, 석박지, 파프리카, 가지는 깍둑\r\n썰고, 두부는 으깬다.","imageUrl":null},{"step":3,"text":"팬에 다진 마늘, 양파, 석박지를 넣어\r\n볶다가 두부를 넣고 수분이 없어질\r\n때까지 볶다가 가지, 파프리카도\r\n넣어 볶는다","imageUrl":null},{"step":4,"text":"밥과 저염된장, 후춧가루를 넣고\r\n볶다가 들기름을 넣어 한 번 더\r\n볶는다.","imageUrl":null},{"step":5,"text":"그릇에 담고 으깬 단호박과\r\n세발나물을 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00215_2.png', 644.9, 20.15, 3.33, 1.14, 505.1),
  ('216', '닭고기볶음밥', '밥', ' 쌀(80g), 완두콩(10g), 닭고기(100g), 대추(10g), 수삼(20g)
양파(20g), 당근(10g),강황가루(3g), 맛술(15g)', '["쌀","완두콩","닭고기","대추","수삼","양파","당근","강황가루","맛술"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','5fd34bed-4339-4fcc-9221-f082ce6ac652','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','b371c5d2-f12b-47ee-9a87-26efd09db09d','9f4dacdc-b7a6-43f9-ab9b-6a3b28042318','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','a7cf6fb8-b34f-4cfe-a4af-d8e000090dcb','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1']::uuid[], '[{"step":1,"text":"쌀은 30분 정도 불린 뒤 동량의 물에 강황가루를 풀어 완두콩과 함께\r\n넣어 밥을 짓는다.","imageUrl":null},{"step":2,"text":"닭고기를 깨끗이 씻은 후 끓는 물에\r\n살짝 데쳐 기름기를 제거한 뒤 작게\r\n썰어 대추, 수삼과 함께 맛술에 재워\r\n잡냄새를 없앤다.","imageUrl":null},{"step":3,"text":"양파와 당근은 작게 깍둑 썬다.","imageUrl":null},{"step":4,"text":"팬에 기름을 두른 후 재워둔\r\n닭고기와 당근, 양파를 볶는다","imageUrl":null},{"step":5,"text":"강황밥을 넣고 같이 볶아\r\n마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00216_2.png', 622.5, 30.8, 4.73, 3.92, 121),
  ('311', '토마토라면', '일품', ' 애호박(30g), 양파(20g), 청양고추(5g), 대파(5g), 토마토(300g)
라면스프(3g), 라면(100g),다시마(2.5g), 멸치(2.5g), 무(10g), 물(250g)', '["애호박","양파","청양고추","대파","토마토","라면스프","라면","다시마","멸치","무","물"]'::jsonb, ARRAY['88c94a13-dc8a-4e66-ab19-08fc2ea82c77','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','b85df3ba-e324-47fa-b25d-d5bb552b8590','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','dd2eee03-8bbf-44ff-8a7f-ed1443986711','f80c9a7d-1510-44e2-a82b-28b9f684e191','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"냄비에 육수 재료를 넣고 10분간\r\n끓여 건더기를 건진다.","imageUrl":null},{"step":2,"text":"애호박은 돌려 깎아 채 썰고, 양파도\r\n채 썰고, 청양고추와 대파는\r\n어슷 썬다.","imageUrl":null},{"step":3,"text":"토마토는 200g은 잘게 다지고,\r\n100g은 두툼하게 썬다.","imageUrl":null},{"step":4,"text":"육수에 라면스프와 라면을 넣고\r\n살짝 익힌 뒤 양파, 애호박, 다진\r\n토마토를 넣고 끓인다.","imageUrl":null},{"step":5,"text":"면이 다 익으면 두툼하게 썬\r\n토마토를 넣고 10초간 더 끓인다.","imageUrl":null},{"step":6,"text":"대파와 청양고추를 올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00311_2.png', 190.4, 4.9, 1.1, 1, 423.2),
  ('312', '토마토샐러드라면', '일품', ' 양상추(80g), 치커리(15g), 굵은 면발 라면(55g), 삶은 닭가슴살(50g)
방울토마토(15g), 파슬리가루(0.1g),설탕(2g), 식초(1.5g), 레몬즙(1g), 저염간장(3g), 다진 마늘(1g),토마토(50g), 다진 양파(4g), 올리브유(1.5g)', '["양상추","치커리","굵은 면발 라면","삶은 닭가슴살","방울토마토","파슬리가루","설탕","식초","레몬즙","저염간장","다진 마늘","토마토","다진 양파","올리브유"]'::jsonb, ARRAY['1389717e-81e4-4350-96d4-d627d851aa10','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','4362c386-a37c-44cd-9254-fafd74712a09','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','f175019d-5a93-4cd4-aabc-e7e79445f15a','fc6e31ce-388e-45cd-956b-b238b9134eb1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc']::uuid[], '[{"step":1,"text":"소스를 만든다.","imageUrl":null},{"step":2,"text":"양상추와 치커리는 굵은 줄기\r\n부분을 빼고 먹기 좋은 크기로 잘게\r\n찢는다.","imageUrl":null},{"step":3,"text":"라면 끓는 물에서 4분간 삶고 체에\r\n건져 찬물에 헹군다.","imageUrl":null},{"step":4,"text":"닭가슴살을 먹기 좋은 크기로 찢어\r\n면과 함께 섞는다.","imageUrl":null},{"step":5,"text":"그릇에 채소와 면을 담고,\r\n방울토마토도 먹기 좋게 잘라\r\n담는다.","imageUrl":null},{"step":6,"text":"소스와 파슬리가루를 뿌려\r\n마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00312_2.png', 360.6, 17.23, 6.55, 3.59, 241.7),
  ('313', '검은깨라면크로켓', '후식', ' 검은깨(8g), 빵가루(80g), 라면(50g), 달걀(45g), 녹말가루(15g),쇠고기(40g), 다진 땅콩(5g), 어린잎채소(2g), 방울토마토(20g),소스 통계피(20g), 생강(10g), 조청(10g), 물엿(20g), 흑설탕(20g),발사믹식초(15g), 올리브유(5g)', '["검은깨","빵가루","라면","달걀","녹말가루","쇠고기","다진 땅콩","어린잎채소","방울토마토","소스 통계피","생강","조청","물엿","흑설탕","발사믹식초","올리브유"]'::jsonb, ARRAY['9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','45080597-55fa-42dc-aa65-12d7694e4b7e','b85df3ba-e324-47fa-b25d-d5bb552b8590','c7d438a6-34d6-423f-905d-446b839e2f39','6613d1d9-80a2-4ce4-9d3d-647203197e53','1c49d1f4-5781-474d-818d-bd7002a4dc0b','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc']::uuid[], '[{"step":1,"text":"검은깨를 곱게 부숴 빵가루와 섞어\r\n마른 팬에서 볶는다.","imageUrl":null},{"step":2,"text":"라면을 삶아 건져 물기를 제거 한 뒤\r\n달걀물→녹말가루 순서대로 묻힌다.","imageUrl":null},{"step":3,"text":"다진 쇠고기에 다진 땅콩을 넣어\r\n반죽해 적당한 크기로 빚는다.","imageUrl":null},{"step":4,"text":"반죽을 라면으로 감싸 달걀물→\r\n빵가루 순으로 입혀 튀긴다.","imageUrl":null},{"step":5,"text":"통계피와 생강을 물(200g)에 넣고\r\n끓여 우려낸 뒤 건더기를 건지고\r\n나머지 소스 재료를 넣고 살짝\r\n조린다.","imageUrl":null},{"step":6,"text":"발사믹드레싱을 만들어\r\n어린잎채소에 뿌리고, 방울토마토는\r\n반으로 썰어 라면 크로켓과 함께\r\n그릇에 담아 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00313_2.png', 396.9, 22.8, 9.11, 11.17, 158),
  ('314', '김말이두부스테이크', '반찬', '두부 100g, 김 2g, 허브소금 1g
소 : 다진쇠고기 20g, 양파20g, 표고버섯10g, 새송이버섯 10g, 밀가루 10g, 흰후추 0.3g
곁들이채소 : 고구마 50g, 단호박 50g, 양파 70g, 아스파라거스 10g
레드와인소스 : 레드와인 25g, 토마토 20g, 마늘 3g, 버터 5g, 올리브유 20g, 허브소금 1g
발사믹식초 15g', '["두부","김","허브소금","소 : 다진쇠고기","양파","표고버섯","새송이버섯","밀가루","흰후추","곁들이채소 : 고구마","단호박","아스파라거스","레드와인소스 : 레드와인","토마토","마늘","버터","올리브유","발사믹식초"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','09229cbc-4574-4002-b726-68c37345bbe9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','66458b1b-c92f-43fa-8eba-e428892ce88a','3f94371a-728f-49ae-8ea9-1a1e87b68048','aab3b0b9-d346-4697-a1c8-1b1530153788','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','98d652af-a6d6-440c-9653-e22fc5d47d88','a8462d27-4ef1-4919-ae9b-10c8f8b9545f','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','fc6e31ce-388e-45cd-956b-b238b9134eb1','7aabd532-361f-4240-aa33-6bfa1be4bc4e','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','6c285c60-022a-4a00-b172-87df97f16a2f']::uuid[], '[{"step":1,"text":"두부는 사방 3cm 길이와 두께로 잘라 허브\r\n소금을 뿌려 수분을 완전히 빼고 속을 파서\r\n밀가루를 묻힌다.","imageUrl":null},{"step":2,"text":"소 재료를 골고루 양념해 속을 파준 두부에\r\n채워준다.","imageUrl":null},{"step":3,"text":"채워진 두부를 김을 두른 뒤 팬에 은근하게\r\n구워준다.","imageUrl":null},{"step":4,"text":"고구마, 단호박, 아스파라거스를 편으로\r\n썰어 준다.","imageUrl":null},{"step":5,"text":"마늘과 토마토를 각각 다진 후 오일에 볶다가\r\n레드와인을 넣어 졸인다. 불을 끄기 직전에\r\n버터를 넣어 소스를 만든다.","imageUrl":null},{"step":6,"text":"채소를 각각 구워주고 구워진 두부스테이크를\r\n담고 레드와인 소스를 뿌려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00314_2.png', 279.4, 23, 18.2, 12.7, 22.8),
  ('315', '연어롤샐러드', '반찬', '연어 60g, 단호박 50g, 방울토마토 4개, 시금치 50g, 영양부추 50g
소스 : 잣 5g, 더덕 45g, 마늘 5g, 식초 15g, 올리브오일 30g, 다진홍고추 15g', '["연어","단호박","방울토마토","시금치","영양부추","소스 : 잣","더덕","마늘","식초","올리브오일","다진홍고추"]'::jsonb, ARRAY['35db7cf0-556e-49d8-b6d2-f6e1b1e12e16','98d652af-a6d6-440c-9653-e22fc5d47d88','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','9a7f4da6-531b-4478-89ff-d73beafcad1b','058648c3-fd8e-476d-952f-b15dc67f1877','641252bb-9268-421d-8b9a-314bcbc0c522','fc6e31ce-388e-45cd-956b-b238b9134eb1','6c285c60-022a-4a00-b172-87df97f16a2f','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','30b5d53c-d247-4f04-9b50-c0f728e65cf9']::uuid[], '[{"step":1,"text":"영양부추, 시금치는 먹기 좋게 잘라 물에\r\n담가준다.","imageUrl":null},{"step":2,"text":"단호박은 삶아서 체에 내려준다.","imageUrl":null},{"step":3,"text":"토마토는 곱게 다져주고 시금치도 데친 후\r\n단호박, 연두부와 섞어준다.","imageUrl":null},{"step":4,"text":"연어를 포를 떠서 만들어진 단호박과 연두부를\r\n연어에 돌돌 말아 냉동실에 살짝 얼려준다.","imageUrl":null},{"step":5,"text":"소스재료로 소스를 만든다.","imageUrl":null},{"step":6,"text":"접시에 준비된 채소를 깔고 연어를 올리고\r\n소스를 올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00315_2.png', 208.5, 1.1, 19.5, 14, 51),
  ('316', '비타민이유식', '일품', '멜론 300g, 브로콜리 30g, 감자 60g, 요거트 15g, 설탕 5g', '["멜론","브로콜리","감자","요거트","설탕"]'::jsonb, ARRAY['9bf64924-ce53-42bb-849e-7294416e95d6','20894da1-739d-4d52-b5fe-4943bd3492d5','bb41a88a-ea2b-4830-876d-91fe7f640296','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"브로콜리는 데쳐낸 후 송송 다져준다.","imageUrl":null},{"step":2,"text":"감자는 삶아준 후 체에 내려준다.","imageUrl":null},{"step":3,"text":"멜론은 씨를 제거하고 껍질을 벗긴 후 믹서에\r\n갈아 체에 내려준다.","imageUrl":null},{"step":4,"text":"체에 내린 감자와 브로콜리 그리고 멜론즙을\r\n함께 섞어준다.","imageUrl":null},{"step":5,"text":"설탕으로 간을 해주고 볼에 담고 요거트로\r\n장식을 해 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00316_2.png', 115.9, 21.9, 2.8, 1.9, 64.1),
  ('317', '한입꼬치구이', '반찬', '통삼겹 200g, 고구마 100g,
대파 40g, 2가지색 미니파프리카 40g, 청피망 40g, 양송이 40g, 건고추 3g,
어간장 10g, 통후추 1g, 로즈마리 1g. 마늘기름 15g
소스 : 오렌지주스 100g, 레몬즙 15g, 올리고당 15g, 후추 1g, 다진마늘 10g', '["통삼겹","고구마","대파","청피망","양송이","건고추","어간장","통후추","로즈마리","소스 : 오렌지주스","레몬즙","올리고당","후추","다진마늘"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','4b410642-7bf9-45ad-9055-e7d9a34edaa1','df459e6f-3515-45d5-8c9a-9d37b6249379','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','f175019d-5a93-4cd4-aabc-e7e79445f15a','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','722e0bf6-fae4-4bb8-bb95-f7b407b085d7','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"통삼겹살은 어간장, 마늘기름, 로즈마리,\r\n통후추에 재워준다.","imageUrl":null},{"step":2,"text":"양송이, 피망, 파프리카는 먹기 좋게 썰어서\r\n마늘기름에 구워준다.","imageUrl":null},{"step":3,"text":"고구마는 먹기 좋게 잘라 기름 없이 구워준다.","imageUrl":null},{"step":4,"text":"재워 놓은 통삼겹은 작은 크기로 잘라서\r\n건고추를 넣어 물에 데쳐낸다.","imageUrl":null},{"step":5,"text":"모든 재료를 꼬치에 끼워서 살짝 구워준다.","imageUrl":null},{"step":6,"text":"레몬껍질을 채 썰어서 소스를 만들어주고\r\n꼬치와 함께 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00317_2.png', 289.9, 9, 12.1, 22.9, 33.7),
  ('318', '간장곤약볶음국수', '일품', '곤약국수 200g, 사과 60g, 레몬즙 15g
볶음양념 : 맛간장 30g, 다진생강 3g, 다진양파 15g, 버터 10g
소스 : 다진양파 10g, 흑임자 7g, 플레인요거트 30g, 그라놀라 30g, 꿀 10g', '["곤약국수","사과","레몬즙","볶음양념 : 맛간장","다진생강","다진양파","버터","소스 : 다진양파","흑임자","플레인요거트","그라놀라","꿀"]'::jsonb, ARRAY['c85a52b9-c3b4-4a76-951c-bb40edeb3adb','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','7aabd532-361f-4240-aa33-6bfa1be4bc4e','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','bb41a88a-ea2b-4830-876d-91fe7f640296','286d1783-cd34-4aae-ac8b-006529ec8bc5']::uuid[], '[{"step":1,"text":"곤약은 세척 후 물기를 빼준다.","imageUrl":null},{"step":2,"text":"사과는 가늘게 채 썰어 레몬에 살짝 담가 주고,\r\n다진양파도 레몬즙에 살짝 담가준다.","imageUrl":null},{"step":3,"text":"팬에 다진양파를 버터에 볶다가 나머지 볶음\r\n재료를 넣고 볶음양념을 만들어준다.","imageUrl":null},{"step":4,"text":"볶음양념에 곤약 을 넣 어 고들고들하게\r\n볶아준다.","imageUrl":null},{"step":5,"text":"사과를 물기를 완전히 제거하고 소스재료를\r\n섞어 곁들이 소스를 만들어준다.","imageUrl":null},{"step":6,"text":"볶음곤약을 그릇에 담고 그라놀라를 뿌려서\r\n완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00318_2.png', 133, 18.3, 1.2, 6.1, 343.1),
  ('319', '닭가슴살리조또', '밥', '닭가슴살 100g, 찰보리 50g, 찹쌀 50g, 청피망 50g, 표고버섯 30g, 청양고추 10g, 양파 60g
다진마늘 15g, 홍피망 50g, 생크림 30g, 우유 30g, 올리브오일 50g, 함초소금 2g
고명 : 건조토마토 10g', '["닭가슴살","찰보리","찹쌀","청피망","표고버섯","청양고추","양파","다진마늘","홍피망","생크림","우유","올리브오일","함초소금","고명 : 건조토마토"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','a5bc0b46-0192-496a-b429-d2cb90b2bca9','df459e6f-3515-45d5-8c9a-9d37b6249379','66458b1b-c92f-43fa-8eba-e428892ce88a','30b5d53c-d247-4f04-9b50-c0f728e65cf9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','af187077-b7f6-4b0e-9e99-f844f6359ac2','e937397f-54e2-49df-997a-f393c58360be','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"찹쌀은 30분 정도, 찰보리는 1시간 이상\r\n불려주고 보리쌀은 한번 쪄 준다.","imageUrl":null},{"step":2,"text":"표고버섯은 물에 데친다. 이때 표고버섯 불린\r\n물은 버리지 않고 짜투리 채소와 함께 채소\r\n국물을 만들어준다.","imageUrl":null},{"step":3,"text":"불린 표고버섯, 청피망, 홍피망, 양파, 오리\r\n가슴살은 작은 정사각형으로 잘라주고 청양\r\n고추는 다져준다.","imageUrl":null},{"step":4,"text":"다진 청양고추와 다진마늘은 볶아주고 다시\r\n여기에 다진채소와 가슴살을 볶아준다.","imageUrl":null},{"step":5,"text":"찹쌀과 보리쌀을 넣어 만들어진 채소국물에\r\n끓여주다 생크림과 우유를 넣어 죽 형태로\r\n만든다.","imageUrl":null},{"step":6,"text":"여기에 볶아진 재료를 넣고 소금으로 간을\r\n하고 말린 토마토를 올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00319_2.png', 388.5, 46.7, 17.1, 14.8, 73.1),
  ('320', '녹차귀리라떼', '후식', '브로콜리 60g, 귀리 30g, 닭육수 250ml, 우유150ml
녹차가루 10g, 아몬드슬라이스 20g, 무염버터 5g, 흰후추 3g, 소금 0.5g
우유 50ml, 생크림 50ml, 다진양파 15g', '["브로콜리","귀리","닭육수","우유","녹차가루","아몬드슬라이스","무염버터","흰후추","소금","생크림","다진양파"]'::jsonb, ARRAY['9bf64924-ce53-42bb-849e-7294416e95d6','c15a4a69-31ab-450d-943a-2a7bb2230857','a4c37075-c03b-47bb-8aed-5e907620f5d2','e937397f-54e2-49df-997a-f393c58360be','52ba316f-8e7f-415f-8079-9a9d674c9adf','7aabd532-361f-4240-aa33-6bfa1be4bc4e','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','2cf0c12b-f248-4012-8f53-303c730a7b3d','af187077-b7f6-4b0e-9e99-f844f6359ac2','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742']::uuid[], '[{"step":1,"text":"귀리는 불려준 뒤 닭육수에 삶아준다.","imageUrl":null},{"step":2,"text":"브로콜리는 잘 손질하여 잘게 썰어 놓는다.","imageUrl":null},{"step":3,"text":"양파는 채 썰어 버터로 볶다가 1의 브로콜리와\r\n귀리, 아몬드슬라이스를 넣고 같이 볶아준다.","imageUrl":null},{"step":4,"text":"어느 정도 볶아지면 우유를 넣고 다시 한 번\r\n볶아준다.","imageUrl":null},{"step":5,"text":"닭육수를 넣고 귀리가 익을 때 까지 푹 익힌 후\r\n믹서에 갈아 체에 걸러준다.","imageUrl":null},{"step":6,"text":"마지막으로 생크림을 넣고 농도를 조절하고\r\n녹차가루를 올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00320_2.png', 150.8, 10.4, 5.3, 9.8, 62.4),
  ('321', '계란숙샐러드', '반찬', '달걀 120g, 쇠고기 50g, 게맛살 20g, 감자 1개, 천연조미료 5g, 물 200g
브로콜리 50g, 방울토마토 60g, 미니파프리카 25g, 영양부추 5g
소스 : 매실청 30g, 발사믹식초 15g, 올리브오일 15g, 후추 1g, 식초 15g', '["달걀","쇠고기","게맛살","감자","천연조미료","물","브로콜리","방울토마토","미니파프리카","영양부추","소스 : 매실청","발사믹식초","올리브오일","후추","식초"]'::jsonb, ARRAY['c7d438a6-34d6-423f-905d-446b839e2f39','1c49d1f4-5781-474d-818d-bd7002a4dc0b','20894da1-739d-4d52-b5fe-4943bd3492d5','94786475-832c-4f97-aab7-bf6fbbe2236b','9bf64924-ce53-42bb-849e-7294416e95d6','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','5e79d288-1400-4817-bd20-e5e6041821b1','058648c3-fd8e-476d-952f-b15dc67f1877','6c285c60-022a-4a00-b172-87df97f16a2f','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"소고기에 물을 넣어 육수를 뽑아준 후 천연\r\n조미료로 간을 해준다.","imageUrl":null},{"step":2,"text":"소고기는 곱게 다져준 뒤 볶아준다.","imageUrl":null},{"step":3,"text":"감자를 삶아서 체에 내려준다.","imageUrl":null},{"step":4,"text":"계란을 풀고 소고기 다진 것과 게맛살, 물을\r\n넣고 섞은 뒤 찜기에 쪄준다.","imageUrl":null},{"step":5,"text":"부추와 브로콜리는 뜨거운 물에 데쳐 먹기\r\n좋게 잘라주고, 방울토마토와 미니파프리카도\r\n먹기 좋게 잘라준다.","imageUrl":null},{"step":6,"text":"매실청과 올리브오일, 후추로 드레싱을 만들어\r\n준비된 채소를 섞어준 뒤 그릇에 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00321_2.png', 96.2, 6.5, 53.9, 5.2, 112.5),
  ('322', '한식풍닭가슴살스테이크', '일품', '닭가슴살 280g, 미나리 50g, 쌀 50g, 청경채 60g
무조림 : 무 150g, 맛간장 15g, 고춧가루 15g, 다진마늘 5g, 물 200g
소스 : 된장 15g, 매실청 15g, 들기름 10g, 다진양파 10g, 검은깨 5g, 다진마늘 5g', '["닭가슴살","미나리","쌀","청경채","무조림 : 무","맛간장","고춧가루","다진마늘","물","소스 : 된장","매실청","들기름","다진양파","검은깨"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','dc7b2b73-74de-4fb8-9274-a5967ca444f9','a5bc0b46-0192-496a-b429-d2cb90b2bca9','7ac59c14-e767-4f32-a2e5-d558c1a29dfb','f175019d-5a93-4cd4-aabc-e7e79445f15a','84104c49-0af4-4323-a56b-b67002a422d9','fc6e31ce-388e-45cd-956b-b238b9134eb1','94786475-832c-4f97-aab7-bf6fbbe2236b','02fd7135-0ec3-49ec-82e3-390536ab2cf5','f5534afd-2a26-4493-8ec1-fd680dcb3bef','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"미나리는 데친 후 먹기 좋은 크기로 잘라서\r\n밥을 해준다.","imageUrl":null},{"step":2,"text":"닭가슴살에 밥을 넣고 말아서 오븐에 굽는다.","imageUrl":null},{"step":3,"text":"무는 물에 익히고 고춧가루와 무조림 재료를\r\n넣어 졸여준다.","imageUrl":null},{"step":4,"text":"청경채는 데친 후 팬에 살짝 볶아준다.","imageUrl":null},{"step":5,"text":"소스를 만들어준다.","imageUrl":null},{"step":6,"text":"접시에 무조림을 깔고 닭가슴살 구이를 올리고\r\n청경채와 함께 소스를 뿌려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00322_2.png', 191.5, 10, 24.4, 6, 294),
  ('323', '강황고구마밥', '밥', '쌀 100g, 강황가루 15g, 고구마 50g, 닭육수 300g
양념장 : 영양부추 10g, 다진청고추 15g, 다진홍고추 15g, 다진양파 15g, 간편 어간장 15g', '["쌀","강황가루","고구마","닭육수","양념장 : 영양부추","다진청고추","다진홍고추","다진양파","간편 어간장"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','a7cf6fb8-b34f-4cfe-a4af-d8e000090dcb','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','a4c37075-c03b-47bb-8aed-5e907620f5d2','30b5d53c-d247-4f04-9b50-c0f728e65cf9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742']::uuid[], '[{"step":1,"text":"먼저 영양부추를 뺀 재료로 양념장을 30분\r\n전에 만들어준다.","imageUrl":null},{"step":2,"text":"쌀은 30분전에 불려주고 고구마는 껍질째\r\n작은 깍두기 모양으로 잘라 냉수에 담가준다.","imageUrl":null},{"step":3,"text":"닭육수에 강황가루를 풀어주고 쌀과 고구마를\r\n고루 섞어 밥을 해준다.","imageUrl":null},{"step":4,"text":"만들어진 양념장에 영양부추를 한입 크기로\r\n잘라 최종 양념장을 만들어준다.","imageUrl":null},{"step":5,"text":"그릇에 강황고구마밥을 담아주고 양념장과\r\n함께 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00323_2.png', 251.1, 54.1, 4.3, 1.9, 164.7),
  ('324', '된장시금치옹심이', '국&찌개', '시금치 150g, 감자 80g, 애호박 30g, 당근 20g, 양파 50g
청고추 15g, 홍고추 15g, 밀가루 30g
국물 : 바지락 100g, 저염된장 25g, 볶은소금 1g', '["시금치","감자","애호박","당근","양파","청고추","홍고추","밀가루","국물 : 바지락","저염된장","볶은소금"]'::jsonb, ARRAY['9a7f4da6-531b-4478-89ff-d73beafcad1b','20894da1-739d-4d52-b5fe-4943bd3492d5','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','30b5d53c-d247-4f04-9b50-c0f728e65cf9','aab3b0b9-d346-4697-a1c8-1b1530153788','392236b1-82e9-4e38-bd12-6a53b80bf463','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"바지락은 볶은 소금에 담가 해감을 시켜준다.","imageUrl":null},{"step":2,"text":"물 400g에 저염 된장과 바지락을 넣어 국물을\r\n만들어준다.","imageUrl":null},{"step":3,"text":"시금치 는 데 친 후 물기를 제거해 송송\r\n다져준다.","imageUrl":null},{"step":4,"text":"당근, 양파와 청홍고추는 채 썰고 애호박과\r\n감자는 반달모양으로 썰어준다.","imageUrl":null},{"step":5,"text":"다진 시금치와 밀가루를 이용해 완자를\r\n만들어준다.","imageUrl":null},{"step":6,"text":"만들어진 국물에 옹심이를 넣어 끓여주고\r\n나머지 채소를 넣어 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00324_2.png', 167.3, 25.1, 14.9, 0.8, 771),
  ('62', '불고기 소스를 곁들인 두부구이', '반찬', ' 두부 70g(1/5모), 전분 10g(2작은술), 흑임자 2g(1/3작은술), 식용유 5g(1작은술), 후추약간
, 간장 3g(2/3작은술), 올리고당 3g(2/3작은술), 생강즙 3g(2/3작은술), 물 30ml(2큰술)', '["두부","전분","흑임자","식용유","후추","간장","올리고당","생강즙","물"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','6613d1d9-80a2-4ce4-9d3d-647203197e53','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','a7a59e81-de3d-4893-b56a-b2218732a25b','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','f175019d-5a93-4cd4-aabc-e7e79445f15a','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"두부를 2.5×2.5×1cm 정도로 잘라 물기를 빼고 후추를 뿌린 후 전분가루를 골고루 묻혀\r\n식용유를 둘러 프라이팬에 갈색이 나도록 양면을 굽는다.","imageUrl":null},{"step":2,"text":"프라이팬에 간장, 올리고당, 생강즙, 물을 넣어 끓여 불고기 양념을 만든 후 양념을 구운 두부에 넣고 졸인다.","imageUrl":null},{"step":3,"text":"그릇에 두부를 담고 위에 흑임자를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00062_2.png', 200, 7, 12, 14, 481),
  ('140', '매생이순두부탕', '국&찌개', ' 풋고추 5g(1/3개), 순두부 80g(1/3모), 매생이 120g, 홍합 120g
, 다시마 20g(10cm), 멸치 60g(10개), 보리된장 15g(1큰술)', '["풋고추","순두부","매생이","홍합","다시마","멸치","보리된장"]'::jsonb, ARRAY['30b5d53c-d247-4f04-9b50-c0f728e65cf9','4566cac5-9166-4c0d-906a-bfc7360f8f5b','1ddd4301-779b-4e99-a008-4933509afaf7','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','dd2eee03-8bbf-44ff-8a7f-ed1443986711']::uuid[], '[{"step":1,"text":"매생이는 씻어 체에 거른다.","imageUrl":null},{"step":2,"text":"물 250g에 다시마, 멸치, 보리된장을 넣어 육수를 만든다.","imageUrl":null},{"step":3,"text":"육수가 끓으면 매생이, 홍합, 순두부를 넣어 끓인 후 고추를 고명으로 올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00140_2.png', 10.4, 1.1, 1.1, 0.2, 131.8),
  ('144', '겨자 오이고추소박이', '반찬', ' 오이고추 15g(1개), 당근 5g(5cm), 무 5g(5cm), 부추 5g(6cm), 양파 5g(5cm)
, 겨자분말 5g(1작은술), 식초 10g(2작은술), 설탕 10g(2작은술)', '["오이고추","당근","무","부추","양파","겨자분말","식초","설탕"]'::jsonb, ARRAY['e38c12a7-43cb-421a-a36e-7ef0d32517fa','f80c9a7d-1510-44e2-a82b-28b9f684e191','058648c3-fd8e-476d-952f-b15dc67f1877','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"겨자분말은 물에 섞은 후, 뜨거운 물 3g에 중탕하여 발효시킨 후 설탕과 식초를 넣어 겨자 소스를 만들고 당근, 무, 양파는 0.1×5cm로 채 썬다.","imageUrl":null},{"step":2,"text":"부추는 3cm 길이로 썬다.","imageUrl":null},{"step":3,"text":"오이 고추는 길게 칼집을 넣어 씨를 제거한 다음 4cm로 썰고 당근, 무, 양파, 부추를 겨자냉채소스와 버무려 오이고추의 속을 채워 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00144_2.png', 36.9, 7.9, 1.2, 0.1, 43.4),
  ('145', '실치오이 초절임', '반찬', '매실액 10g(2작은술), 실치 40g(1컵), 식초 20g(1⅓큰술), 오이 80g(1/2개)', '["매실액","실치","식초","오이"]'::jsonb, ARRAY['02fd7135-0ec3-49ec-82e3-390536ab2cf5','6c285c60-022a-4a00-b172-87df97f16a2f','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a']::uuid[], '[{"step":1,"text":"실치는 끓는 물에 데친다.","imageUrl":null},{"step":2,"text":"오이는 반달 모양으로 슬라이스하고 식초에 절인 후 물기를 제거하고 매실액을 넣는다.","imageUrl":null},{"step":3,"text":"데쳐낸 실치와 오이를 함께 버무려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00145_2.png', 36.9, 6.1, 3, 0, 59.1),
  ('146', '비트무절임', '반찬', ' 무 200g(1/3개), 비트 10g(5cm), 쪽파 10g(10cm)
, 소금 2g(1/2작은술), 식초 20g(1⅓큰술), 설탕 10g(2작은술)', '["무","비트","쪽파","소금","식초","설탕"]'::jsonb, ARRAY['f80c9a7d-1510-44e2-a82b-28b9f684e191','524e1b82-1f81-4648-b50c-441404a06786','4b410642-7bf9-45ad-9055-e7d9a34edaa1','2cf0c12b-f248-4012-8f53-303c730a7b3d','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"비트는 강판에 갈아 비트 물을 만든다.","imageUrl":null},{"step":2,"text":"무는 채 썰고 비트 물에 채 썬 무를 넣어 색을 들인다.","imageUrl":null},{"step":3,"text":"초절이 소스를 만든 후 색을 입힌 무를 소스에 넣어 재우고 절인 무를 건져 그릇에 담고 0.5cm로 썬 쪽파를 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00146_2.png', 38.4, 8.5, 1, 0, 13.3),
  ('150', '감귤 김치', '반찬', ' 배추 10g(1/60개), 미나리 5g, 홍고추 5g(1/2개), 소금 5g(1작은술)
, 귤 100g(1개), 고춧가루 5g(1작은술), 다진 마늘 10g(2작은술), 생강즙 5g(1작은술)', '["배추","미나리","홍고추","소금","귤","고춧가루","다진 마늘","생강즙"]'::jsonb, ARRAY['e116f85b-0eaa-40cb-8107-df5ec8486ad4','dc7b2b73-74de-4fb8-9274-a5967ca444f9','30b5d53c-d247-4f04-9b50-c0f728e65cf9','2cf0c12b-f248-4012-8f53-303c730a7b3d','bbf5a336-7a76-423e-a6a3-7f79147e5218','84104c49-0af4-4323-a56b-b67002a422d9','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9']::uuid[], '[{"step":1,"text":"귤은 껍질을 까서 믹서에 갈아 체에 내린다.","imageUrl":null},{"step":2,"text":"배추는 3×3cm로 썰어 소금에 절인 후 체에 받치고 미나리, 홍고추는 길이 3cm로 썬다.","imageUrl":null},{"step":3,"text":"귤즙에 고춧가루, 생강즙, 다진 마늘을 넣고 김치 국물을 만들고 배추, 미나리, 홍고추에 김치 국물을 부어 실온에 2일 숙성시킨다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00150_2.png', 21.2, 4.6, 0.6, 0, 64.9),
  ('231', '두부달걀덮밥', '밥', ' 두부(50g), 가지(20g), 표고버섯(30g), 양파(10g), 달걀(15g)
밥(200g), 가다랑어포(1g),재료 물(200g), 다시마(1g), 가다랑어포(1g),후춧가루(0.1g), 녹말가루(1g), 청주(1g), 설탕(1g), 간장(2g), 녹말물(18g)', '["두부","가지","표고버섯","양파","달걀","밥","가다랑어포","재료 물","다시마","후춧가루","녹말가루","청주","설탕","간장","녹말물"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','3e12cf79-2cde-4309-9f7c-4eccce3fde28','66458b1b-c92f-43fa-8eba-e428892ce88a','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','c7d438a6-34d6-423f-905d-446b839e2f39','ecb35816-34ae-4c4c-867a-e3f84db92755','47fc4ccd-d88e-4a88-9b91-e6147e571342','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','6613d1d9-80a2-4ce4-9d3d-647203197e53','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','06e6f3e7-0293-469d-a338-11a610f3e71b','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"찬물에 다시마를 넣고 끓여 건져\r\n내고 불을 끈 후 가다랑어포를\r\n넣어 우려 육수를 만든다.","imageUrl":null},{"step":2,"text":"두부, 가지는 깍둑 썰고, 표고버섯,\r\n양파는 채 썰고, 달걀은 곱게 푼다.","imageUrl":null},{"step":3,"text":"두부, 가지는 물기를 제거한 뒤\r\n후춧가루로 밑간하고 녹말가루를\r\n얇게 입혀 식용유를 두른 팬에서\r\n구워 건진다.","imageUrl":null},{"step":4,"text":"육수(1컵)에 청주, 설탕, 간장을 넣고\r\n표고버섯, 양파를 넣고 조려 덮밥\r\n소스를 만든다.","imageUrl":null},{"step":5,"text":"달걀물을 붓고 익을 때까지 저은 후\r\n녹말물을 넣어 되직하게 끓인다.","imageUrl":null},{"step":6,"text":"밥을 그릇에 담고 덮밥소스를\r\n곁들인 후 두부, 가지, 가다랑어포를\r\n얹어 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00231_2.png', 669.4, 19.35, 3.91, 6.2, 311.6),
  ('232', '봄나물밥', '밥', ' 현미(30g), 멥쌀(60g), 쑥갓(20g), 달래(10g)
, 고추장(5g), 된장(5g), 다시마 육수(60g), 두부(15g)', '["현미","멥쌀","쑥갓","달래","고추장","된장","다시마 육수","두부"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','10ccd1c9-12d7-4075-b2cc-bfc87ce891b6','e4d65d59-99e9-4321-889d-5df57d5b0e18','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','392236b1-82e9-4e38-bd12-6a53b80bf463','4566cac5-9166-4c0d-906a-bfc7360f8f5b']::uuid[], '[{"step":1,"text":"현미는 1시간 정도, 멥쌀은 30분 정도 각각 불린 뒤 섞는다.","imageUrl":null},{"step":2,"text":"쑥갓과 달래는 줄기부분과 잎으로 나누어 1㎝ 길이로 썬다.","imageUrl":null},{"step":3,"text":"쑥갓과 달래의 줄기부분은 불린 쌀과 함께 냄비에 넣고 밥물을 맞춰 센 불에서 끓어오르면 중약 불로 줄여 밥을 15분간 짓는다.","imageUrl":null},{"step":4,"text":"약한 불로 줄여 밥을 뜸 들인다.","imageUrl":null},{"step":5,"text":"다시마육수를 제외한 두부 양념장 재료를 믹서에 곱게 갈아 다시마 육수, 남겨둔 나물의 잎을 팬에 넣어 끓여 두부장을 만든다","imageUrl":null},{"step":6,"text":"나물밥에 두부장을 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306041839_1678087119869.jpg', 254.3, 54.4, 6.6, 1.2, 138.3),
  ('233', '가지연어구이', '반찬', ' 가지(40g), 토마토(20g), 연어(200g), 파슬리가루(1g)
올리브유(5g), 마늘(10g),사과(20g), 유자청(30g), 레몬즙(5g)', '["가지","토마토","연어","파슬리가루","올리브유","마늘","사과","유자청","레몬즙"]'::jsonb, ARRAY['3e12cf79-2cde-4309-9f7c-4eccce3fde28','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','35db7cf0-556e-49d8-b6d2-f6e1b1e12e16','4362c386-a37c-44cd-9254-fafd74712a09','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','fc6e31ce-388e-45cd-956b-b238b9134eb1','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','ff5b6cbe-7985-4ca2-94ad-5525717cddf1','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67']::uuid[], '[{"step":1,"text":"가지는 어슷 썰고, 토마토는 반\r\n자른다.","imageUrl":null},{"step":2,"text":"연어는 파슬리와 올리브유에 재운다.","imageUrl":null},{"step":3,"text":"마늘은 노릇하게 굽는다.","imageUrl":null},{"step":4,"text":"재운 연어와 가지, 토마토는 180℃로\r\n예열한 오븐에 10분 정도 굽는다.","imageUrl":null},{"step":5,"text":"사과는 잘게 다져 유자청과\r\n레몬즙을 넣고 살짝 볶아 소스를\r\n만든다.","imageUrl":null},{"step":6,"text":"연어, 가지, 토마토, 구운 마늘을\r\n담고 소스를 얹어 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00233_2.png', 318.2, 9.85, 15.8, 6.19, 83.4),
  ('234', '갈릭칩동태구이', '반찬', ' 동태포(150g), 통마늘(10g),맛술(10g), 저염된장(10g)', '["동태포","통마늘","맛술","저염된장"]'::jsonb, ARRAY['fc6e31ce-388e-45cd-956b-b238b9134eb1','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','392236b1-82e9-4e38-bd12-6a53b80bf463']::uuid[], '[{"step":1,"text":"동태는 맛술과 저염된장에 담가\r\n재운다.","imageUrl":null},{"step":2,"text":"마늘은 얇게 편으로 썬 후\r\n식용유(15g)에 노릇하게 튀긴다.","imageUrl":null},{"step":3,"text":"재운 동태는 흐르는 물에 살짝 헹궈\r\n짠맛을 제거한 뒤 물기를 최대한\r\n제거한다.","imageUrl":null},{"step":4,"text":"식용유(15g)를 두른 팬에 동태살을\r\n얹어 부서지지 않게 굽는다.","imageUrl":null},{"step":5,"text":"갈릭칩을 올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00234_2.png', 141.8, 6.74, 20.4, 3.82, 232.3),
  ('235', '고구마두부스테이크', '반찬', '스테이크재료 두부(200g), 고구마(130g), 마늘(15g), 대파(20g)
양파(60g), 다진 견과류(20g), 찹쌀가루(30g)
청국장소스 양송이버섯(20g), 다시마육수(80g), 청국장(15g)
유 자청(10g), 녹말가루(5g)', '["스테이크재료 두부","고구마","마늘","대파","양파","다진 견과류","찹쌀가루","청국장소스 양송이버섯","다시마육수","청국장","유 자청","녹말가루"]'::jsonb, ARRAY['4b4f0113-01cf-4dc6-ae1f-30f09e99746b','fc6e31ce-388e-45cd-956b-b238b9134eb1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4cb11562-015f-4ab5-969f-0ea8483a0b42','6f271236-b557-4340-b3ab-8522098c95df','ff5b6cbe-7985-4ca2-94ad-5525717cddf1','6613d1d9-80a2-4ce4-9d3d-647203197e53']::uuid[], '[{"step":1,"text":"두부는 물기를 없앤 뒤 체에 밭쳐\r\n으깬 뒤 칼등으로 한 번 더 으깬다.","imageUrl":null},{"step":2,"text":"고구마는 삶아 껍질을 벗겨 으깬다.","imageUrl":null},{"step":3,"text":"마늘, 대파, 양파는 잘게 다진 뒤\r\n식용유(5g)를 두른 팬에서 살짝 볶아\r\n키친타월에 밭쳐 물기를 제거하며\r\n식힌다.","imageUrl":null},{"step":4,"text":"볶은 채소, 두부, 고구마,\r\n다진 견과류, 찹쌀가루를 섞은 뒤\r\n반죽해 둥글 납작하게 모양을\r\n빚고, 식용유(15g)를 두른 팬에서\r\n앞뒤로 노릇하게 굽는다.","imageUrl":null},{"step":5,"text":"양송이버섯은 채 썬다.","imageUrl":null},{"step":6,"text":"다시마육수에 청국장, 유자청,\r\n녹말가루, 양송이버섯을 넣고 조린\r\n청국장소스를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00235_2.png', 741.4, 20.8, 7.8, 11, 216.6),
  ('236', '닭가슴살카나페', '반찬', ' 고구마(100g), 우유(110g), 백김치(40g)
비트(40g), 닭가슴살(100g)
후춧가루(0.3g), 새싹(1g), 바나나식초(80g)', '["고구마","우유","백김치","비트","닭가슴살","후춧가루","새싹","바나나식초"]'::jsonb, ARRAY['4b4f0113-01cf-4dc6-ae1f-30f09e99746b','e937397f-54e2-49df-997a-f393c58360be','133f214e-50f4-431d-af36-d97f6c9d4f9b','524e1b82-1f81-4648-b50c-441404a06786','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','bc0ebb76-798a-40fe-be99-557ca2b9a9b4']::uuid[], '[{"step":1,"text":"고구마를 삶아 껍질을 벗겨 으깬 뒤\r\n우유와 섞어 고구마무스를 만든다.","imageUrl":null},{"step":2,"text":"백김치와 비트를 작게 썬 뒤\r\n백김치에 물이 들도록 절여 놓는다.","imageUrl":null},{"step":3,"text":"닭가슴살을 한입 크기로 썬 후\r\n칼등으로 두드린 뒤 후춧가루로\r\n밑간한다.","imageUrl":null},{"step":4,"text":"식용유(15g)를 두른 팬에 닭가슴살을\r\n올려 굽는다.","imageUrl":null},{"step":5,"text":"구운 닭가슴살 위에 고구마무스,\r\n비트에 절인 백김치, 새싹을 얹는다.","imageUrl":null},{"step":6,"text":"그릇에 닭가슴살카나페를 넣은 후\r\n바나나식초를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00236_2.png', 281.4, 16.6, 14.8, 1.96, 202.1),
  ('237', '삼색꼬치구이', '반찬', ' 돼지고기(목살, 120g), 파인애플(30g), 브로콜리(20g), 방울토마토(40g),배(30g), 사과(50g), 레몬즙(5g), 꿀(5g)', '["돼지고기","파인애플","브로콜리","방울토마토","배","사과","레몬즙","꿀"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','c97290bd-7146-45bc-8e7f-28390e7a95b0','9bf64924-ce53-42bb-849e-7294416e95d6','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','286d1783-cd34-4aae-ac8b-006529ec8bc5']::uuid[], '[{"step":1,"text":"껍질을 벗긴 배, 사과를 믹서기에\r\n갈아 레몬즙과 꿀을 넣고\r\n배사과소스를 만든다.","imageUrl":null},{"step":2,"text":"돼지고기와 파인애플은 깍둑 썬다.","imageUrl":null},{"step":3,"text":"브로콜리는 약 2~3cm 크기로 자른\r\n후 끓는 물에 살짝 데친다.","imageUrl":null},{"step":4,"text":"식용유(5g)를 두른 팬에 돼지고기를\r\n한 번 먼저 굽는다.","imageUrl":null},{"step":5,"text":"꼬치에 방울토마토, 구운 돼지고기,\r\n파인애플, 브로콜리 순서로 끼운 후\r\n굽는다.","imageUrl":null},{"step":6,"text":"노릇하게 구운 꼬치구이에\r\n배사과소스를 얹어 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00237_2.png', 255.4, 9.12, 11.9, 6.14, 57),
  ('238', '꽁치채소말이', '반찬', ' 꽁치살(200g), 마늘종(30g), 양파(40g), 파프리카(100g)
밀가루(30g), 깻잎(3g), 무순(8g), 새싹(8g),오렌지(200g), 레몬즙(15g), 설탕(0.3g), 고운 소금(0.3g)', '["꽁치살","마늘종","양파","파프리카","밀가루","깻잎","무순","새싹","오렌지","레몬즙","설탕","고운 소금"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5e79d288-1400-4817-bd20-e5e6041821b1','aab3b0b9-d346-4697-a1c8-1b1530153788','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','f09d1d41-602a-441c-a7bc-520311490ceb','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','19eb37dc-2b1c-4e89-a931-31a38ae60561','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"꽁치는 머리와 꼬리를 떼어 내고\r\n포 뜨듯이 길게 살만 발라내 잔뼈를\r\n발라 쌀뜨물에 담갔다 건져 물기를\r\n제거한다.","imageUrl":null},{"step":2,"text":"오렌지를 간 뒤 레몬즙과 설탕,\r\n소금을 섞어 오렌지소스를 만든다.","imageUrl":null},{"step":3,"text":"마늘종은 꽁치 폭에 맞춰 썰고,\r\n양파와 파프리카도 채 썬다.","imageUrl":null},{"step":4,"text":"수분을 제거한 꽁치에 밀가루를\r\n묻혀 깻잎→마늘종→양파→\r\n파프리카 순으로 올려 돌돌 말아\r\n꼬치로 꽂아 고정한다.","imageUrl":null},{"step":5,"text":"밀가루를 묻히고 달군 팬에\r\n앞뒤가 노릇노릇하게 익힌다.","imageUrl":null},{"step":6,"text":"소스를 팬에 넣고 끓이다가 꽁치\r\n꼬치를 넣고 졸인 뒤 그릇에 무순,\r\n새싹과 함께 담아 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00238_2.png', 523, 10.3, 13.7, 12.6, 93.7),
  ('239', '차돌박이구이', '반찬', ' 연근(30g), 미나리(20g), 오렌지(50g), 오렌지주스(50g)
차돌박이(60g), 어린잎채소(10g),설탕(5g), 홍초(20g), 물(10g)', '["연근","미나리","오렌지","오렌지주스","차돌박이","어린잎채소","설탕","홍초","물"]'::jsonb, ARRAY['b20f623d-e722-42af-9bd1-7c11b5e15aa6','dc7b2b73-74de-4fb8-9274-a5967ca444f9','19eb37dc-2b1c-4e89-a931-31a38ae60561','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"연근은 얇게 3㎜ 정도의 두께로 썰어\r\n홍초물에 담가 절인다.","imageUrl":null},{"step":2,"text":"미나리는 연근과 비슷한 길이로\r\n썬다.","imageUrl":null},{"step":3,"text":"오렌지는 껍질은 얇게 벗겨 채 썰고,\r\n과육부분은 반달 모양으로 2조각\r\n썬다.","imageUrl":null},{"step":4,"text":"과육을 오렌지주스와 섞은 뒤 갈아\r\n오렌지소스를 만든다.","imageUrl":null},{"step":5,"text":"팬에 차돌박이를 펼친 뒤\r\n오렌지소스를 조금씩 넣으며 익힌다.","imageUrl":null},{"step":6,"text":"그릇에 연근초절임, 미나리,\r\n어린잎채소, 차돌박이 순서로\r\n담은 뒤 오렌지 껍질과\r\n오렌지소스를 얹어 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00239_2.png', 210.2, 9.64, 8.88, 8.33, 32),
  ('240', '간장아귀찜', '반찬', ' 아귀(150g), 새우(20g), 미나리(15g), 풋고추(5g), 붉은 고추(5g),콩나물(30g), 참기름(3g), 참깨(1g),설탕(1g), 저염간장(3g), 청주(15g), 다시마물(50g),다진 양파(50g), 다진 생강(5g), 다진 마늘(10g)', '["아귀","새우","미나리","풋고추","붉은 고추","콩나물","참기름","참깨","설탕","저염간장","청주","다시마물","다진 양파","다진 생강","다진 마늘"]'::jsonb, ARRAY['6f10b4ad-53a2-4a07-ba89-19a6b074373d','dc7b2b73-74de-4fb8-9274-a5967ca444f9','30b5d53c-d247-4f04-9b50-c0f728e65cf9','2db049b2-f39c-47ba-857f-fa02b3b0c610','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','06e6f3e7-0293-469d-a338-11a610f3e71b','f175019d-5a93-4cd4-aabc-e7e79445f15a','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"아귀는 얇게 포를 뜬다.","imageUrl":null},{"step":2,"text":"새우를 다져 아귀포 안에 채워 넣은\r\n뒤 데친 미나리로 묶는다.","imageUrl":null},{"step":3,"text":"냄비에 간장소스, 아귀,\r\n아귀찜양념을 넣고 약한 불에서\r\n끓인다.","imageUrl":null},{"step":4,"text":"아귀가 익으면 고추를 어슷 썰어\r\n올린 뒤 살짝 더 익힌다.","imageUrl":null},{"step":5,"text":"콩나물은 끓는 물에 데친 뒤 참기름,\r\n참깨를 넣고 무친다.","imageUrl":null},{"step":6,"text":"아귀찜에 콩나물무침을 곁들여\r\n마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00240_2.png', 100.5, 1.15, 15.1, 0.76, 119.3),
  ('241', '견과류통삼겹살찜', '반찬', ' 돼지고기(통삼겹살, 200g), 땅콩(15g), 아몬드(5g), 말린 자두(15g)
호두(15g), 새우젓(5g), 마늘(20g), 파프리카(45g), 부추(15g),밑간 간장(5g), 참기름(5g), 후춧가루(1g),들기름(5g), 고춧가루(5g),설탕(15g), 맛술(10g), 간장(5g), 닭육수(50g), 다진 마늘(5g),양파(10g), 다진 생강(5g), 다진 당근(5g)', '["돼지고기","땅콩","아몬드","말린 자두","호두","새우젓","마늘","파프리카","부추","밑간 간장","참기름","후춧가루","들기름","고춧가루","설탕","맛술","간장","닭육수","다진 마늘","양파","다진 생강","다진 당근"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','52ba316f-8e7f-415f-8079-9a9d674c9adf','7651578f-1206-499d-a04c-15f034d4cae2','8f2077de-dbd0-4372-a4c2-f987388f16b3','fc6e31ce-388e-45cd-956b-b238b9134eb1','5e79d288-1400-4817-bd20-e5e6041821b1','058648c3-fd8e-476d-952f-b15dc67f1877','0c0ade94-cfd8-4104-b44c-40e942cac482','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','f5534afd-2a26-4493-8ec1-fd680dcb3bef','84104c49-0af4-4323-a56b-b67002a422d9','06e6f3e7-0293-469d-a338-11a610f3e71b','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','f175019d-5a93-4cd4-aabc-e7e79445f15a','a4c37075-c03b-47bb-8aed-5e907620f5d2','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','e38c12a7-43cb-421a-a36e-7ef0d32517fa']::uuid[], '[{"step":1,"text":"통삼겹살은 속을 판 뒤 땅콩, 아몬드,\r\n말린 자두, 호두로 채운 뒤\r\n돼지고기 밑간에 재워 놓는다.","imageUrl":null},{"step":2,"text":"통삼겹살을 김 오른 찜기에 넣어\r\n찐다.","imageUrl":null},{"step":3,"text":"물기를 뺀 새우젓과 편 썬\r\n마늘을 기름에 튀긴다.","imageUrl":null},{"step":4,"text":"소스 재료를 끓인다.","imageUrl":null},{"step":5,"text":"파프리카는 채 썰고, 부추는 먹기\r\n좋은 크기로 썰어 들기름과\r\n고춧가루에 버무린다.","imageUrl":null},{"step":6,"text":"통삼겹살을 먹기 좋은 크기로 썰어\r\n부추, 파프리카 위에 놓고 튀긴\r\n새우젓과 마늘을 올린 뒤 소스를\r\n곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00241_2.png', 745.4, 6, 14.9, 29, 282.4),
  ('242', '닭가슴살말이', '반찬', ' 닭가슴살(150g), 당근(10g), 시금치(10g),표고버섯(10g), 간장(5g), 참기름(3g), 견과류(16g),설탕(3g), 식초(10g),설탕(28g), 발효겨자(28g), 식초(28g), 다진 잣(4g), 다진 땅콩(4g), 참깨(4g)', '["닭가슴살","당근","시금치","표고버섯","간장","참기름","견과류","설탕","식초","발효겨자","다진 잣","다진 땅콩","참깨"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','e38c12a7-43cb-421a-a36e-7ef0d32517fa','9a7f4da6-531b-4478-89ff-d73beafcad1b','66458b1b-c92f-43fa-8eba-e428892ce88a','f175019d-5a93-4cd4-aabc-e7e79445f15a','0c0ade94-cfd8-4104-b44c-40e942cac482','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f','bbbbd533-8922-4dac-9e4c-cd93ea710c92','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"닭가슴살은 곱게 다진다.","imageUrl":null},{"step":2,"text":"당근은 채 썰어서 단촛물에 5분 정도 절이고, 시금치는 데쳐서 물기를 제거하고, 마른 표고버섯은 불린 뒤 곱게 채를 썰어 간장과 참기름에 버무린다.","imageUrl":null},{"step":3,"text":"종이포일에 다진 가슴살을 올리고 그 위에 시금치, 당근, 표고버섯과 견과류를 올려 말아준다","imageUrl":null},{"step":4,"text":"김 오른 찜기에 넣어서 25분간 찐다.","imageUrl":null},{"step":5,"text":"겨자소스를 만든다.","imageUrl":null},{"step":6,"text":"닭가슴살말이에 겨자소스를 곁들여\r\n마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00242_2.png', 233.1, 3.98, 2.22, 3.59, 113.6),
  ('243', '두부말이찜', '반찬', ' 두부(150g), 불린 표고버섯(50g), 닭가슴살(100g)
톳(50g), 깻잎(10g), 참기름(5g),다진 파(10g), 다진 마늘(10g), 부순 참깨(5g),설탕(2g), 레몬즙(3g), 간장(0.5g), 식초(2g)', '["두부","불린 표고버섯","닭가슴살","톳","깻잎","참기름","다진 파","다진 마늘","부순 참깨","설탕","레몬즙","간장","식초"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','f3f07b4b-1a27-4a6d-be6d-09e58352e063','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','0c0ade94-cfd8-4104-b44c-40e942cac482','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','06e6f3e7-0293-469d-a338-11a610f3e71b','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','f175019d-5a93-4cd4-aabc-e7e79445f15a','6c285c60-022a-4a00-b172-87df97f16a2f']::uuid[], '[{"step":1,"text":"두부는 으깨어 면포에 물기를 짜고,\r\n불린 표고버섯도 물기를 꼭 짠 뒤\r\n다지고, 닭가슴살은 곱게 다진다.","imageUrl":null},{"step":2,"text":"두부, 표고버섯, 닭가슴살에\r\n반죽양념을 넣어 치댄다.","imageUrl":null},{"step":3,"text":"톳은 데쳐서 송송 썬다.","imageUrl":null},{"step":4,"text":"쿠킹포일에 참기름을 바르고 반죽을\r\n펼친 뒤 깻잎을 얹고 그 위에 톳을\r\n올려 김밥 말듯이 만다.","imageUrl":null},{"step":5,"text":"쿠킹 포일에 구멍을 내고 김이 오른\r\n찜통에 10-15분 정도 찐다.","imageUrl":null},{"step":6,"text":"두부말이가 식으면 적당한 크기로\r\n썬 뒤 레몬소스를 살짝 뿌려\r\n마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00243_2.png', 250.6, 19.4, 1.64, 5.51, 90.5),
  ('244', '미나리명태찜', '반찬', ' 미나리(20g), 명태(150g), 후춧가루(0.1g),설탕(7g), 레몬(108g), 식초(6g), 저염간장(4g)', '["미나리","명태","후춧가루","설탕","레몬","식초","저염간장"]'::jsonb, ARRAY['dc7b2b73-74de-4fb8-9274-a5967ca444f9','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','06e6f3e7-0293-469d-a338-11a610f3e71b','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','6c285c60-022a-4a00-b172-87df97f16a2f','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"레몬소스를 만들어 약한 불에\r\n졸인다.","imageUrl":null},{"step":2,"text":"미나리는 4cm 간격으로 썬 뒤\r\n잎 부분을 레몬소스에 버무려\r\n놓는다.","imageUrl":null},{"step":3,"text":"즙을 짜고 남은 레몬은 얇게 썰어\r\n준비한다.","imageUrl":null},{"step":4,"text":"명태는 손질한 뒤 후춧가루를 뿌려\r\n밑간한다.","imageUrl":null},{"step":5,"text":"김 오른 찜기에 면포를 깔고 명태를\r\n올린 뒤 미나리줄기와 얇게 썬\r\n레몬을 올려서 중간 불에서 10분,\r\n약한 불에서 10분 정도 찐다.","imageUrl":null},{"step":6,"text":"명태가 다 익으면 레몬소스에\r\n버무린 미나리 잎과 남은\r\n레몬소스를 끼얹어 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00244_2.png', 119.4, 0.03, 19.9, 1.03, 137.3),
  ('340', '불고기덮밥', '밥', '쌀밥 200g, 소불고기 150g, 양파 60g, 청고추 15g, 홍고추 18g
팽이버섯 20g, 계란 60g, 쪽파 15g, 마늘기름 30g, 통깨 5g
양념장 : 맛간장 15g, 생강청 15g, 다진마늘 10g, 다진대파 10g, 흰후추 1g, 참기름 5g', '["쌀밥","소불고기","양파","청고추","홍고추","팽이버섯","계란","쪽파","마늘기름","통깨","양념장 : 맛간장","생강청","다진마늘","다진대파","흰후추","참기름"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','30b5d53c-d247-4f04-9b50-c0f728e65cf9','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','c7d438a6-34d6-423f-905d-446b839e2f39','4b410642-7bf9-45ad-9055-e7d9a34edaa1','34302eb3-407c-41e6-b9ae-89f6123f4b65','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','fc6e31ce-388e-45cd-956b-b238b9134eb1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"소 불고기는 양념장을 버무려 팬에 볶아준다.","imageUrl":null},{"step":2,"text":"청고추, 홍고추는 가늘게 채 썰어준다.","imageUrl":null},{"step":3,"text":"양파는 채 썰고 쪽파도 한입 크기로 잘라준다.","imageUrl":null},{"step":4,"text":"팽이도 먹기 좋은 크기로 잘라준다.","imageUrl":null},{"step":5,"text":"계란물을 풀어준다.","imageUrl":null},{"step":6,"text":"채소를 각각 볶아주다가 볶은 불고기에 섞어\r\n주고 계란물을 풀어서 밥에 올려서 통깨를\r\n뿌려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00340_2.png', 332.5, 58.3, 12.6, 5.4, 192.5),
  ('341', '바비큐리조또', '밥', '통삼겹 200g
조림장 : 맛간장 30g, 통후추 2g, 발사믹식초 30g, 흰후추 1g
청국장리조뜨 : 밥 150g, 청국장가루 15g, 야채육수 200g, 감자 30g
올리브오일 15g, 영양부추 20g
곁들이채소 : 적양배추 30g, 사과 70g, 마늘 25g, 올리브오일 10g', '["통삼겹","조림장 : 맛간장","통후추","발사믹식초","흰후추","청국장리조뜨 : 밥","청국장가루","야채육수","감자","올리브오일","영양부추","곁들이채소 : 적양배추","사과","마늘"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','6c285c60-022a-4a00-b172-87df97f16a2f','6f271236-b557-4340-b3ab-8522098c95df','20894da1-739d-4d52-b5fe-4943bd3492d5','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','058648c3-fd8e-476d-952f-b15dc67f1877','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"사과와 적양배추는 먹기 좋은 크기로 잘라준다.","imageUrl":null},{"step":2,"text":"감자를 작은 깍두기 모양으로 자르고 영양부추는\r\n송송 잘라주어 청국장 리조또를 만들어준다.","imageUrl":null},{"step":3,"text":"준비된 곁들이 채소를 올리브오일에 볶아준다.","imageUrl":null},{"step":4,"text":"준비된 통삼겹은 물에 한번 80% 이상 데쳐준 후\r\n조림장 재료에 물 200g을 넣고 은근히 졸여서\r\n익혀준다.","imageUrl":null},{"step":5,"text":"조림장에 졸여지는 통삼겹에 장이 한 큰술\r\n남을 정도까지 졸여준다.","imageUrl":null},{"step":6,"text":"접시에 곁들이 채소와 청국장 리조또를 함께\r\n올려 셋팅한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00341_2.png', 301, 39.4, 10.5, 11.2, 269.9),
  ('342', '간편콩국수', '일품', '메밀면 80g, 백일송이 25g, 마늘기름 15g, 통깨 2g, 볶은소금 1g
고명 : 애호박 50g, 양파 50g, 청고추 15g, 홍고추 15g
국물 : 두유 200g, 두부 60g', '["메밀면","백일송이","마늘기름","통깨","볶은소금","고명 : 애호박","양파","청고추","홍고추","국물 : 두유","두부"]'::jsonb, ARRAY['b85df3ba-e324-47fa-b25d-d5bb552b8590','34302eb3-407c-41e6-b9ae-89f6123f4b65','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','2cf0c12b-f248-4012-8f53-303c730a7b3d','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4566cac5-9166-4c0d-906a-bfc7360f8f5b']::uuid[], '[{"step":1,"text":"두유와 두부를 믹서에 생수 100g을 넣고\r\n갈아준다.","imageUrl":null},{"step":2,"text":"애호박은 돌려깎기 해서 채 썰어주고 양파,\r\n홍고추, 청고추도 가늘게 채 썰어준다.","imageUrl":null},{"step":3,"text":"백일송이는 가늘게 찢어 볶아준다.","imageUrl":null},{"step":4,"text":"애호박, 당근, 청고추, 홍고추를 각각 볶아준다.","imageUrl":null},{"step":5,"text":"메밀면을 삶아서 준비한다.","imageUrl":null},{"step":6,"text":"볼에 메밀면을 담고 고명을 올려준 후 믹서\r\n에 갈은 두부두유를 뿌려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00342_2.png', 229.9, 26.2, 12.3, 8.4, 183.4),
  ('343', '모듬해물찜', '반찬', '전복 200g, 자숙새우 60g, 소라살 45g, 알마늘 20g, 대파 15g
청고추 15g, 홍고추 15g, 홍피망 15g, 양파 50g
양념장 : 멕시코고추 2g, 맛간장 30g, 올리고당 15g, 참기름 15g, 흰후추 1g, 물 200g', '["전복","자숙새우","소라살","알마늘","대파","청고추","홍고추","홍피망","양파","양념장 : 멕시코고추","맛간장","올리고당","참기름","흰후추","물"]'::jsonb, ARRAY['5678a9c5-5df5-4a97-8f95-77df12578956','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','df459e6f-3515-45d5-8c9a-9d37b6249379','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','f175019d-5a93-4cd4-aabc-e7e79445f15a','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','0c0ade94-cfd8-4104-b44c-40e942cac482','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"자숙새우와 소라살은 한번 데친 후 소라살은\r\n먹기 좋게 잘라준다.","imageUrl":null},{"step":2,"text":"전복은 껍질을 벗기지 말고 세척해 준다.","imageUrl":null},{"step":3,"text":"양파, 홍피망, 대파는 먹기 좋게 잘라준다.","imageUrl":null},{"step":4,"text":"청고추, 홍고추도 먹기 좋게 잘라준다.","imageUrl":null},{"step":5,"text":"데친 물 200g에 양념장을 만들어 멕시코\r\n고추를 담가 숙성시켜준 뒤 양념장에 알마늘을\r\n넣어 끓여준다.","imageUrl":null},{"step":6,"text":"만들어진 양념장에 소라, 전복, 자숙새우,\r\n준비된 채소 순으로 넣어 모듬해물찜을 완성\r\n한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00343_2.png', 156.3, 12, 21, 2.7, 1010.5),
  ('344', '크렌베리귀리밥', '밥', '백미 150g, 크렌베리 15g, 귀리 20g', '["백미","크렌베리","귀리"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','c15a4a69-31ab-450d-943a-2a7bb2230857']::uuid[], '[{"step":1,"text":"백미와 귀리는 세척해 백미는 30분, 귀리는\r\n1시간 정도 불려준다.","imageUrl":null},{"step":2,"text":"귀리를 먼저 물을 넣어 볶아 충분히 익혀준다.","imageUrl":null},{"step":3,"text":"귀리가 어느 정도 익을 때 쯤 쌀을 섞어 한 번\r\n더 볶아준다.","imageUrl":null},{"step":4,"text":"귀뢰와 쌀이 익어갈 때 쌀의 물 1배를 넣고\r\n밥을 해 준다.","imageUrl":null},{"step":5,"text":"불을 끄고 크린베리를 바로 넣어서 뚜껑을\r\n덮어 5분 후에 밥을 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00344_2.png', 494.2, 104.3, 9.6, 4.3, 22.4),
  ('345', '블루베리냉스프', '일품', '검은콩두유 50g, 꿀 15g, 딸기 20g, 블루베리 20g
저지방우유 50g, 볶은현미 20g, 바나나 50g
고명 : 브로콜리 15g, 라이스페이퍼 1장, 건조체리 15g', '["검은콩두유","꿀","딸기","블루베리","저지방우유","볶은현미","바나나","고명 : 브로콜리","라이스페이퍼","건조체리"]'::jsonb, ARRAY['286d1783-cd34-4aae-ac8b-006529ec8bc5','60a7c3e6-e703-4fb0-b5d9-0119a5deab83','203b7165-14df-4cb6-b165-e4dadf9a3079','a5bc0b46-0192-496a-b429-d2cb90b2bca9','1a4b39f8-b581-46dc-bd7e-289cd6160711','241e49d7-4aa4-4411-8ded-350a16b41222','115c21d5-f619-42df-a91e-58fccd4b2459']::uuid[], '[{"step":1,"text":"브로콜리는 먹기 좋게 잘라서 데쳐준다.","imageUrl":null},{"step":2,"text":"건조체리는 손질해 씨를 제거하고 송송 다져서\r\n먹기 좋게 잘라준다.","imageUrl":null},{"step":3,"text":"라이스페이퍼를 뜨거운 물에 데쳐내 체리를\r\n말아 체리 만두를 만든다.","imageUrl":null},{"step":4,"text":"만들어진 체리 만두를 팬에 살짝 구워서\r\n라이스페이퍼를 고소하게 만든다.","imageUrl":null},{"step":5,"text":"블루베리, 딸기, 바나나, 검은콩두유와 우유를\r\n한데 섞어 믹서에 갈아준다.","imageUrl":null},{"step":6,"text":"갈아둔 스프를 담고 브로콜리와 체리 만두를\r\n올리고 먹기 전에 볶은 현미를 올려준다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00345_2.png', 115.7, 20.6, 2.2, 2.7, 32.8),
  ('346', '토마토제철나물 샐러드', '반찬', '영양부추 20g, 치커리 20g, 적양배추 50g, 알배추 30g, 방울토마토 100g, 양파70g
두부크루통 : 두부 60g, 식용유 20g
