  ('493', '표고크림파스타', '일품', '양송이(20g), 표고버섯(80g), 소금(0.5g), 후춧가루(0.02g)
스파게티(100g), 올리브오일(10g)
, 밀가루(10g), 버터(10g), 우유(200g)
생크림(20g)', '["양송이","표고버섯","소금","후춧가루","스파게티","올리브오일","밀가루","버터","우유","생크림"]'::jsonb, ARRAY['48a4fd5a-e4f6-467b-9e3f-445334e0ee04','66458b1b-c92f-43fa-8eba-e428892ce88a','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','b85df3ba-e324-47fa-b25d-d5bb552b8590','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','aab3b0b9-d346-4697-a1c8-1b1530153788','7aabd532-361f-4240-aa33-6bfa1be4bc4e','e937397f-54e2-49df-997a-f393c58360be','af187077-b7f6-4b0e-9e99-f844f6359ac2']::uuid[], '[{"step":1,"text":"양송이는 껍질을 벗겨 형태 그대로\r\n썰고, 표고버섯은 기둥을 제거하고\r\n편으로 썰어놓는다.","imageUrl":null},{"step":2,"text":"팬에 버터를 살짝 넣고 썰어놓은\r\n버섯을 소금을 살짝 뿌려 볶아 준비한다.","imageUrl":null},{"step":3,"text":"냄비에 버터와 밀가루를 넣고, 은근히\r\n볶아 화이트루를 만든다.","imageUrl":null},{"step":4,"text":"화이트 루에 우유를 조금씩 넣고 뭉치지\r\n않게 풀어 끓이다가 다시 생크림을 넣고\r\n한 소큼 끓여 놓는다.","imageUrl":null},{"step":5,"text":"스파게티는 끓는 물에 약 10분 정도\r\n삶아 건져 올리브 오일에 볶아 접시에\r\n담는다.","imageUrl":null},{"step":6,"text":"끓여 놓은 크림소스에 볶아진 버섯과\r\n후춧가루를 넣고 한 소큼 더 끓여\r\n스파게티를 담은 접시에 넣고 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00493_2.png', 332.5, 54.6, 10.8, 7.8, 107),
  ('494', '떡갈비통치미국수', '일품', '동치미(400g), 배(30g), 식초(10g), 다진 소고기(30g)
오이(20g), 당근(20g), 양파(10g), 후춧가루(0.2g), 정종(2g)
설탕(10g), 저염간장(5g), 다진 마늘(10g), 다진 대파(10g)
