  ('656', '버섯배추말이', '반찬', '배추(5장), 양배추(20g), 표고버섯(2개), 만송이버섯(50g),
미나리(30g), 다시마(20g), 식초(20g), 설탕(20g), 소금(0.2g),
저염간장(20g)', '["배추","양배추","표고버섯","만송이버섯","미나리","다시마","식초","설탕","소금","저염간장"]'::jsonb, ARRAY['e116f85b-0eaa-40cb-8107-df5ec8486ad4','fd4254d4-2691-47e1-9367-c2b820ef8d00','66458b1b-c92f-43fa-8eba-e428892ce88a','dc7b2b73-74de-4fb8-9274-a5967ca444f9','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','2cf0c12b-f248-4012-8f53-303c730a7b3d','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"버섯은 채썬다.","imageUrl":null},{"step":2,"text":"끓는 물에 채썰어 놓은 버섯을\r\n데쳐낸다.","imageUrl":null},{"step":3,"text":"다시마는 물에 담궈 다시마 물을\r\n만들어 식초와 설탕 저염간장을 넣고\r\n골고루 섞어 소스를 만들어 놓는다.","imageUrl":null},{"step":4,"text":"미나리는 끓는 물에 소금을 넣고\r\n데친다.","imageUrl":null},{"step":5,"text":"배추는 끓는 물에 양배추와 함께 데쳐\r\n찬물에 헹구고 양배추는 채 썬다.","imageUrl":null},{"step":6,"text":"김발에 데친 배추를 놓고 표고버섯,\r\n만송이버섯, 미나리, 양배추 채를 넣고\r\n돌돌 말아 먹기 좋게 썰어 접시에 담은\r\n뒤 소스를 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00656_2.png', 95.4, 17.3, 5.4, 0.5, 500),
  ('657', '봄날의 연못', '반찬', '문어(100g), 양파(30g), 오이(30g), 배(1/4개), 토마토(50g),
유자청(30g), 레몬(1/4개), 올리브오일(10g), 라임(1/2개)', '["문어","양파","오이","배","토마토","유자청","레몬","올리브오일","라임"]'::jsonb, ARRAY['55a34ec2-28ee-407c-8ad5-7462cbe99d55','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','ff5b6cbe-7985-4ca2-94ad-5525717cddf1','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc']::uuid[], '[{"step":1,"text":"끓는 물에 문어를 넣고 약 10분 정도\r\n삶아 건진다.","imageUrl":null},{"step":2,"text":"라임은 얇게 썬다.","imageUrl":null},{"step":3,"text":"삶은 문어를 얇게 저미고 라임을 한 장\r\n한 장 넣고 숙성 시킨다.","imageUrl":null},{"step":4,"text":"양파, 오이는 채썬다.","imageUrl":null},{"step":5,"text":"배와 토마토는 주사위 모양으로 썬다.","imageUrl":null},{"step":6,"text":"유자청, 레몬, 올리브오일, 소금으로\r\n소스를 만들고, 접시에 문어와 라임을\r\n담고 그 옆에 썰어 놓은 야채와 과일을\r\n올려 소스를 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00657_2.png', 191.1, 26.5, 20.3, 0.4, 318.5),
  ('658', '산나물 유부초밥', '밥', '취나물(50g), 참나물(30g), 곤드레나물(30g), 유부(50g),
쌀(200g), 식초(20g), 설탕(30g), 소금(0.2g), 토마토(30g)', '["취나물","참나물","곤드레나물","유부","쌀","식초","설탕","소금","토마토"]'::jsonb, ARRAY['50e01736-309e-4164-8982-c5239f6dc17f','09065cd3-28cc-4a82-8b3e-5121054c7482','a5bc0b46-0192-496a-b429-d2cb90b2bca9','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','2cf0c12b-f248-4012-8f53-303c730a7b3d','aa597bcd-596b-4cbe-a2c4-3da0d060cb50']::uuid[], '[{"step":1,"text":"쌀은 깨끗이 씻어 30분 정도 불린 뒤\r\n고슬고슬하게 밥을 짓는다.","imageUrl":null},{"step":2,"text":"취나물과 참나물은 끓는 물에 소금을\r\n넣고 데쳐 헹군다.","imageUrl":null},{"step":3,"text":"곤드레나물은 충분히 불려 삶아\r\n헹군다.","imageUrl":null},{"step":4,"text":"유부는 끓는 물에 살짝 데쳐 기름기를\r\n제거 하고 반으로 자른다.","imageUrl":null},{"step":5,"text":"식초, 설탕, 소금을 섞어 촛물을\r\n만든다.","imageUrl":null},{"step":6,"text":"촛물을 밥에 섞고 준비한 나물을 다져\r\n골고루 섞고 데친 유부에 넣고 초밥을\r\n만들어 접시에 담은 뒤 나물과\r\n토마토를 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00658_2.png', 304, 51.8, 10.4, 6.1, 72.8),
  ('659', '삼삼한 롤', '반찬', '연어(훈제연어, 120g), 양파(30g), 아보카도(1/4개), 당근(30g),
감자(50g), 새송이버섯(1개), 레몬(1/4개), 사워크림(50g),
소금(0.2g)', '["연어","양파","아보카도","당근","감자","새송이버섯","레몬","사워크림","소금"]'::jsonb, ARRAY['35db7cf0-556e-49d8-b6d2-f6e1b1e12e16','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','906bfef3-a41b-40d3-acda-7d8f23d2bcd2','e38c12a7-43cb-421a-a36e-7ef0d32517fa','20894da1-739d-4d52-b5fe-4943bd3492d5','3f94371a-728f-49ae-8ea9-1a1e87b68048','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','1cab0c39-b27a-4e4e-b125-fd5216fe8b24','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"훈제연어는 길게 손질한다","imageUrl":null},{"step":2,"text":"아보카도는 길게 채 썬다.","imageUrl":null},{"step":3,"text":"양파, 당근, 새송이버섯도 길게 채\r\n썬다.","imageUrl":null},{"step":4,"text":"감자는 삶아 체에 내려 소금과\r\n사워크림을 넣고 잘 섞어서 틀에\r\n담는다.","imageUrl":null},{"step":5,"text":"팬에 양파, 당근, 새송이버섯을 각각\r\n볶는다.","imageUrl":null},{"step":6,"text":"사워크림과 레몬즙을 섞어 소스를\r\n만들고 훈제 연어에 준비된 야채를\r\n넣고 돌돌 말아 먹기 좋게 썰어 접시에\r\n담고, 한쪽에 감자를 담은 뒤\r\n사워소스를 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00659_2.png', 323.6, 9.7, 33.7, 16.7, 189.8),
  ('660', '삼색채소 냉파스타', '일품', '닭고기(가슴살, 100g), 파스타(100g), 쥬키니호박(50g),
사과(1/4개), 비트(50g), 레몬(1/4개), 마늘(20g), 시금치(30g),
소금(0.2g), 올리브오일(20g), 꿀(20g)', '["닭고기","파스타","쥬키니호박","사과","비트","레몬","마늘","시금치","소금","올리브오일","꿀"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','524e1b82-1f81-4648-b50c-441404a06786','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','fc6e31ce-388e-45cd-956b-b238b9134eb1','9a7f4da6-531b-4478-89ff-d73beafcad1b','2cf0c12b-f248-4012-8f53-303c730a7b3d','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','286d1783-cd34-4aae-ac8b-006529ec8bc5']::uuid[], '[{"step":1,"text":"끓는 물에 파스타를 넣고 약 10분 정도\r\n삶아 건져 올리브오일을 살짝 바른다.","imageUrl":null},{"step":2,"text":"쥬키니 호박은 채썰어 소금에 절인 뒤\r\n볶는다.","imageUrl":null},{"step":3,"text":"닭가슴살은 마늘을 넣고 삶은 뒤 먹기\r\n좋게 찢는다.","imageUrl":null},{"step":4,"text":"사과와 비트, 레몬을 믹서에 갈아\r\n소스를 만든다.","imageUrl":null},{"step":5,"text":"소스에 꿀을 넣어 맛을 내고 차갑게\r\n보관한다.","imageUrl":null},{"step":6,"text":"팬에 삶아 놓은 파스타를 넣고 볶다가\r\n닭살과 호박채, 시금치를 넣고 볶은 뒤\r\n접시에 담고 차갑게 보관한 소스를\r\n올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00660_2.png', 323.2, 51.1, 13.6, 7.2, 50.9),
  ('661', '새우보리죽 고등어스테이크', '일품', '고등어(1/2마리), 새우(3마리), 보리(100g), 생강(10g),
레몬(1/4개), 막걸리(50g), 비트(50g), 설탕(20g), 식초(20g),
소금(0.2g)', '["고등어","새우","보리","생강","레몬","막걸리","비트","설탕","식초","소금"]'::jsonb, ARRAY['f7f9c0c6-98d6-45b9-bbbe-26b57a62ee2e','6f10b4ad-53a2-4a07-ba89-19a6b074373d','2ca24a23-b88d-4b79-a029-a0748b0850ab','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','524e1b82-1f81-4648-b50c-441404a06786','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"새우는 껍질을 벗겨 손질한다.","imageUrl":null},{"step":2,"text":"보리는 깨끗이 씻어 불린다.","imageUrl":null},{"step":3,"text":"불린 보리와 새우에 5배 정도 물을 넣고\r\n죽을 쑨다.","imageUrl":null},{"step":4,"text":"고등어는 포를 뜬다.","imageUrl":null},{"step":5,"text":"포 뜬 고등어에 생강, 레몬, 막걸리를\r\n넣고 비린맛을 제거한다.","imageUrl":null},{"step":6,"text":"비트에 설탕, 식초, 소금을 넣고 피클을\r\n만들고, 보리죽이 끓으면 포 뜬\r\n고등어를 넣고 은근히 익힌다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00661_2.png', 541.5, 88.4, 25.3, 9.6, 140.7),
  ('662', '소금없는 초밥', '밥', '참치(100g), 파프리카(50g), 아스파라거스(3개), 표고버섯(2개),
달걀(2개), 밥(200g), 김(10g), 다시마(100g), 무(30g),
가쓰오부시(20g), 와사비(20g), 식초(20g), 설탕(20g),
소금(0.1g)', '["참치","파프리카","아스파라거스","표고버섯","달걀","밥","김","다시마","무","가쓰오부시","와사비","식초","설탕","소금"]'::jsonb, ARRAY['770b2134-ddc5-454c-bbd7-8e21c4e96c45','5e79d288-1400-4817-bd20-e5e6041821b1','a8462d27-4ef1-4919-ae9b-10c8f8b9545f','66458b1b-c92f-43fa-8eba-e428892ce88a','c7d438a6-34d6-423f-905d-446b839e2f39','ecb35816-34ae-4c4c-867a-e3f84db92755','09229cbc-4574-4002-b726-68c37345bbe9','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','f80c9a7d-1510-44e2-a82b-28b9f684e191','ab5df4e1-070b-41c7-ba70-8b254b4a5b82','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"냄비에 다시마와 무를 넣고 끓이다가\r\n가쓰오부시를 넣고 불을 꺼 진한\r\n육수를 만든다.","imageUrl":null},{"step":2,"text":"육수에 식초, 설탕, 소금을 넣고 촛물을\r\n만든다.","imageUrl":null},{"step":3,"text":"참치는 불에 타다끼 한 뒤 두툼하게\r\n썬다.","imageUrl":null},{"step":4,"text":"파프리카는 직화로 겉만 태워 참치\r\n크기로 썬다.","imageUrl":null},{"step":5,"text":"아스파라거스와 표고버섯은 살짝 데쳐\r\n편으로 썬다.","imageUrl":null},{"step":6,"text":"육수에 달걀을 풀어 두툼하게 지단을\r\n부쳐 썰고, 밥에 촛물을 넣고 골고루\r\n섞어 초밥을 만든 뒤 와사비, 참치,\r\n달걀, 표고버섯, 파프리카 순으로 올려\r\n김으로 띠를 두른다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00662_2.png', 521.6, 80.3, 26.7, 10.4, 172),
  ('725', '잣소스새송이볶음', '반찬', '새송이 버섯 30g, 빨간 파프리카 10g, 노란 파프리카 10g, 찹쌀가루 20g, 물 30g, 소금 0.25g, 올리브유 4g, 잣 5g, 꿀 0.5g, 우유 5g, 소금 0.25g', '["새송이 버섯","빨간 파프리카","노란 파프리카","찹쌀가루","물","소금","올리브유","잣","꿀","우유"]'::jsonb, ARRAY['3f94371a-728f-49ae-8ea9-1a1e87b68048','4cb11562-015f-4ab5-969f-0ea8483a0b42','94786475-832c-4f97-aab7-bf6fbbe2236b','2cf0c12b-f248-4012-8f53-303c730a7b3d','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','bbbbd533-8922-4dac-9e4c-cd93ea710c92','286d1783-cd34-4aae-ac8b-006529ec8bc5','e937397f-54e2-49df-997a-f393c58360be']::uuid[], '[{"step":1,"text":"새송이버섯과 파프리카는 가늘게 채썬다.","imageUrl":null},{"step":2,"text":"채선 야채는 팬에 기름을 두르고 살짝 볶아낸다.","imageUrl":null},{"step":3,"text":"찹쌀가루, 물, 소금을 섞어 찹쌀 반죽을 만든다.","imageUrl":null},{"step":4,"text":"팬에 기름을 두르고 반죽을 한 스푼씩 떠 넣어 동그랗게 부친다.","imageUrl":null},{"step":5,"text":"소스 재료를 모두 넣어 믹서에 간다.","imageUrl":null},{"step":6,"text":"채소볶음을 잣소스에 무쳐 찹쌀전병 위에 한 스푼씩 올려낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102053_1416273653440.jpg', 151.4, 3.2, 7.7, 18.7, 168.2),
  ('727', '더덕얼갈이겉절이', '반찬', '얼갈이 배추 50g, 더덕 20g, 까나리액젓 3g, 고춧가루 1.7g, 깨소금 1g, 다진 파 2.5g, 다진 마늘 1.25g, 다진 생강 0.65g, 소금 0.5g, 국간장 3g, 물 10g', '["얼갈이 배추","더덕","까나리액젓","고춧가루","깨소금","다진 파","다진 마늘","다진 생강","소금","국간장","물"]'::jsonb, ARRAY['641252bb-9268-421d-8b9a-314bcbc0c522','5fd46a51-6998-4ac9-a1fb-cab1eedf7cd9','84104c49-0af4-4323-a56b-b67002a422d9','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','2cf0c12b-f248-4012-8f53-303c730a7b3d','f175019d-5a93-4cd4-aabc-e7e79445f15a','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"얼갈이는 깨끗이 씻어 한입 크기로 뜯는다.","imageUrl":null},{"step":2,"text":"더덕은 껍질을 벗긴다.","imageUrl":null},{"step":3,"text":"껍질 벗긴 더덕은 굵게 채 썰어 소금물에 담가둔다.","imageUrl":null},{"step":4,"text":"양념장 재료를 모두 섞어 양념장을 만든다.","imageUrl":null},{"step":5,"text":"더덕을 건져 물기를 제거한다.","imageUrl":null},{"step":6,"text":"더덕과 얼갈이 배추에 양념장을 넣고 가볍게 버무린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102056_1416273656078.jpg', 35.5, 4.6, 2.6, 1.3, 448.4),
  ('728', '과일겨자채', '반찬', '사과 25g, 배 50g, 밤 10g, 대추 6g, 곶감 10g, 호두 5g, 땅콩 5g, 양상추 15g, 연겨자 1.25g, 연유 2.5g, 사과식초 2.5g, 꿀 3.5g, 배즙 2.5g', '["사과","배","밤","대추","곶감","호두","땅콩","양상추","연겨자","연유","사과식초","꿀","배즙"]'::jsonb, ARRAY['c85a52b9-c3b4-4a76-951c-bb40edeb3adb','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','5e4a7ae8-e12e-48b6-88d5-fc3521d3dce8','b371c5d2-f12b-47ee-9a87-26efd09db09d','2db5cf59-b4ac-4d7b-8e13-68d143e5f34a','7651578f-1206-499d-a04c-15f034d4cae2','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','1389717e-81e4-4350-96d4-d627d851aa10','5b59cfae-1277-48af-99a6-833687e2da0b','6c285c60-022a-4a00-b172-87df97f16a2f','286d1783-cd34-4aae-ac8b-006529ec8bc5']::uuid[], '[{"step":1,"text":"사과와 배는 사방 2cm 네모로 썰고, 밤도 얇게 썰어준다.","imageUrl":null},{"step":2,"text":"1을 설탕물(물 1컵 + 설탕 2.5g)에 담근다.","imageUrl":null},{"step":3,"text":"대추, 곶감은 굵게 채 썰고 호두, 땅콩은 굵게 다진다.","imageUrl":null},{"step":4,"text":"분량의 재료를 섞어 겨자소스 만든다.","imageUrl":null},{"step":5,"text":"과일을 체에 받쳐 물기를 빼고 소스에 버무린다.","imageUrl":null},{"step":6,"text":"한입 크기로 자른 양상추에 샐러드를 올려낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102058_1416273658950.jpg', 123.6, 16.1, 3.1, 6.2, 109.2),
  ('729', '콜라비물김치', '반찬', '콜라비 10g, 당근 3g, 오이 6g, 청고추 2g, 홍고추 1g, 실파 0.5g, 소금 0.5g, 물 60g, 찹쌀가루 10g, 배 10g, 적양파 10g, 소금 1g', '["콜라비","당근","오이","청고추","홍고추","실파","소금","물","찹쌀가루","배","적양파"]'::jsonb, ARRAY['715e97fc-4781-4f58-8be6-fbfe30b9abe6','e38c12a7-43cb-421a-a36e-7ef0d32517fa','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','2cf0c12b-f248-4012-8f53-303c730a7b3d','94786475-832c-4f97-aab7-bf6fbbe2236b','4cb11562-015f-4ab5-969f-0ea8483a0b42','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742']::uuid[], '[{"step":1,"text":"콜라비, 당근, 오이는 나박 썬다.","imageUrl":null},{"step":2,"text":"고추는 둥글게 썰고 실파는 3cm 길이로 썬다.","imageUrl":null},{"step":3,"text":"콜라비를 소금에 살짝 절인다.","imageUrl":null},{"step":4,"text":"물에 찹쌀을 풀어 찹쌀풀을 쑤어 식힌다.","imageUrl":null},{"step":5,"text":"찹쌀풀에 배와 적양파를 갈아 넣어 국물을 만든다.","imageUrl":null},{"step":6,"text":"국물에 소금을 넣어 간을 맞추고 썰어놓은 채소에 부어 용기에 담아 익혀 먹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102100_1416273660762.jpg', 24.1, 5.3, 0.5, 0.1, 1178.3),
  ('730', '고구마라떼', '후식', '고구마 90g, 우유 100g, 플레인 요거트 30g, 다진 호두 10g, 올리고당 7g, 계피가루 0.25g', '["고구마","우유","플레인 요거트","다진 호두","올리고당","계피가루"]'::jsonb, ARRAY['4b4f0113-01cf-4dc6-ae1f-30f09e99746b','e937397f-54e2-49df-997a-f393c58360be','bb41a88a-ea2b-4830-876d-91fe7f640296','7651578f-1206-499d-a04c-15f034d4cae2','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','5205f393-c02b-4b09-a2d6-42629f7401b9']::uuid[], '[{"step":1,"text":"고구마를 전자렌지에서 익힌다.","imageUrl":null},{"step":2,"text":"전자레인지 마지막 1분이 남았을 때 컵에 우유를 따라 함께 데운다.","imageUrl":null},{"step":3,"text":"거품기로 살짝 저어 거품을 낸다.","imageUrl":null},{"step":4,"text":"고구마의 껍질을 벗겨 작게 잘라 우유, 요거트, 호두, 올리고당을 넣고 믹서에 간다.","imageUrl":null},{"step":5,"text":"거품기로 살짝 저어 거품을 낸다.","imageUrl":null},{"step":6,"text":"잔에 따르고 계피가루를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102102_1416273662245.jpg', 291.7, 42.2, 2.8, 14.7, 70),
  ('731', '홍시곶감화채', '후식', '얼린 홍시 70g, 곶감 30g, 호두 10g, 꿀 20g, 물 70g', '["얼린 홍시","곶감","호두","꿀","물"]'::jsonb, ARRAY['2db5cf59-b4ac-4d7b-8e13-68d143e5f34a','7651578f-1206-499d-a04c-15f034d4cae2','286d1783-cd34-4aae-ac8b-006529ec8bc5','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"홍시의 껍질을 벗긴다.","imageUrl":null},{"step":2,"text":"껍질 벗긴 홍시에 꿀과 물을 넣어 믹서에 간다.","imageUrl":null},{"step":3,"text":"곶감을 갈라 씨를 뺀다.","imageUrl":null},{"step":4,"text":"씨를 빼낸 곶감에 호두를 넣어 만다.","imageUrl":null},{"step":5,"text":"곶감말이를 0.5cm 두게로 썬다.","imageUrl":null},{"step":6,"text":"홍시 간 것에 곶감말이를 띄워 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102102_1416273662979.jpg', 173.2, 38.1, 1.56, 3.44, 3.1),
  ('732', '오징어채소말이와 치킨양념소스', '반찬', '오징어채소말이 : 오징어 몸통 80g, 오이 20g, 빨강파프리카 20g, 노랑파프리카 20g , 토마토케첩 8g, 다진 양파 8g, 물엿 2g, 고추장 2g, 다진 마늘 2.5g', '["오징어채소말이 : 오징어 몸통","오이","빨강파프리카","노랑파프리카","토마토케첩","다진 양파","물엿","고추장","다진 마늘"]'::jsonb, ARRAY['9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','5e79d288-1400-4817-bd20-e5e6041821b1','0136fc6a-3a80-4f4c-8057-10bbf34ea572','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"오징어 몸통을 가르고 껍질을 벗긴 후 씻어서 물기를 제거 한다.","imageUrl":null},{"step":2,"text":"오징어 안쪽에 대각선으로 0.3cm 간격의 칼집을 넣고 반대방향으로도 칼집을 넣는다.","imageUrl":null},{"step":3,"text":"오이와 파프리카는 0.4cm 폭으로 길게 썬다.","imageUrl":null},{"step":4,"text":"오징어의 칼집을 넣지 않은 부분에 오이와 파프리카를 얹고 김밥처럼 말아 실로 엮은 후 찜통에 넣고 찐다.","imageUrl":null},{"step":5,"text":"치킨양념소스는 다진 마늘과 다진 양파를 팬에 기름을 두르지 않고 살짝 구워 향을 낸 후 고추장, 토마토케첩, 물엿을 넣고 소스를 만든다.","imageUrl":null},{"step":6,"text":"익은 오징어 말이는 2~3cm 길이로 썰고 5의 소스를 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102125_1416273685292.jpg', 106.4, 8.2, 15.8, 1, 382.1),
  ('733', '옥수수감자샐러드', '반찬', '감자 70g, 달걀 60g, 옥수수알 10g, 완두콩알 5g, 빨강파프리카 5g, 마요네즈 12g, 호상요구르트 10g, 소금 0.15g', '["감자","달걀","옥수수알","완두콩알","빨강파프리카","마요네즈","호상요구르트","소금"]'::jsonb, ARRAY['20894da1-739d-4d52-b5fe-4943bd3492d5','c7d438a6-34d6-423f-905d-446b839e2f39','5e79d288-1400-4817-bd20-e5e6041821b1','549c7365-28e9-491f-9040-412558f93a5c','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"감자는 익기 쉽도록 토막 내고 완두콩과 옥수수알과 함께 김이 오른 찜통에 10~15분간 찐다.","imageUrl":null},{"step":2,"text":"찐 감자를 으깬다.","imageUrl":null},{"step":3,"text":"달걀은 삶아 흰자는 굵게 다지고 노른자는 체에 곱게 내린다.","imageUrl":null},{"step":4,"text":"파프리카는 옥수수알 크기로 썬다.","imageUrl":null},{"step":5,"text":"2에 완두콩, 옥수수, 파프리카, 달걀 흰자를 넣어 섞는다.","imageUrl":null},{"step":6,"text":"마요네즈, 호상요구르트, 달걀노른자, 소금을 넣어 샐러드드레싱을 만들어 5와 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102126_1416273686634.jpg', 248.6, 14.8, 10.9, 16.1, 212.7),
  ('737', '홍합 쌀옹심이국', '국&찌개', '쌀가루 50g, 감자 25g, 홍합살 20g, 애호박 20g, 달걀노른자 20g, 양파 5g, 다진 파 5g, 국멸치 3g, 홍고추 2.5g, 청고추 2.5g, 다진 마늘 2.5g, 다시마 2g, 국간장 2g, 현미유 1g, 소금 0.3g, 물 250g', '["쌀가루","감자","홍합살","애호박","달걀노른자","양파","다진 파","국멸치","홍고추","청고추","다진 마늘","다시마","국간장","현미유","소금","물"]'::jsonb, ARRAY['4cb11562-015f-4ab5-969f-0ea8483a0b42','20894da1-739d-4d52-b5fe-4943bd3492d5','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','c7d438a6-34d6-423f-905d-446b839e2f39','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','dd2eee03-8bbf-44ff-8a7f-ed1443986711','30b5d53c-d247-4f04-9b50-c0f728e65cf9','fc6e31ce-388e-45cd-956b-b238b9134eb1','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','f175019d-5a93-4cd4-aabc-e7e79445f15a','a7a59e81-de3d-4893-b56a-b2218732a25b','2cf0c12b-f248-4012-8f53-303c730a7b3d','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"물 1컵 반에 홍합, 국멸치, 건다시마, 양파를 넣고 멸치다시마국물 1컵을 내고 다시마는 건져 채 썬다.","imageUrl":null},{"step":2,"text":"감자는 껍질을 벗겨 찜통에 찐 후 으깬다.","imageUrl":null},{"step":3,"text":"2의 재료에 쌀가루, 달걀노른자, 현미유, 소금을 넣고 반죽하여 구슬크기의 옹심이를 10개 정도 만든다.","imageUrl":null},{"step":4,"text":"호박은 돌려깍기하여 2cm 가량으로 채 썰고 파, 홍고추, 청고추는 어슷썰기 한다.","imageUrl":null},{"step":5,"text":"멸치다시마국물이 끓으면 옹심이를 넣고 익어서 떠오르면 홍합, 호박, 다진 파, 다진 마늘, 다시마를 넣고 국간장으로 간을 한다.","imageUrl":null},{"step":6,"text":"홍고추와 청고추로 장식한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101955_1416273595773.jpg', 317.2, 46.8, 11.7, 8.3, 498.8),
  ('738', '찬밥김치달걀찜', '반찬', '달걀 50g, 밥 30g(쌀 13g), 김장김치 20g, 당근 5g, 양파 5g, 파 5g, 새우젓국물 2g, 물 100g', '["달걀","밥","김장김치","당근","양파","파","새우젓국물","물"]'::jsonb, ARRAY['c7d438a6-34d6-423f-905d-446b839e2f39','ecb35816-34ae-4c4c-867a-e3f84db92755','e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"배추김치는 속을 털어낸다.","imageUrl":null},{"step":2,"text":"1의 김치를 다진 다음 물기를 짠다.","imageUrl":null},{"step":3,"text":"당근, 양파, 파는 잘게 다진다.","imageUrl":null},{"step":4,"text":"달걀은 흰자와 노른자를 체에 거른다.","imageUrl":null},{"step":5,"text":"달걀에 물 반컵을 넣고 잘 저은 후 1,2의 재료와 찬밥을 섞고 새우젓으로 간을 한다.","imageUrl":null},{"step":6,"text":"5를 찜통에 넣고 찐다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101957_1416273597162.jpg', 134.2, 12.2, 7.9, 5.7, 465.7),
  ('739', '꼬막떡꼬치구이', '반찬', '꼬막 60g(꼬막살 20g), 떡볶이떡 40g 고추장 8g, 양파 10g, 파 5g, 조청 3g, 현미유 3g, 다진 마늘 2.5g, 간장 1g, 고춧가루 1g, 참기름 1g, 통깨 0.5g', '["꼬막","떡볶이떡","양파","파","조청","현미유","다진 마늘","간장","고춧가루","참기름","통깨"]'::jsonb, ARRAY['af336608-1eeb-4b10-9a3a-1df0ad140ccb','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','a7a59e81-de3d-4893-b56a-b2218732a25b','fc6e31ce-388e-45cd-956b-b238b9134eb1','f175019d-5a93-4cd4-aabc-e7e79445f15a','84104c49-0af4-4323-a56b-b67002a422d9','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"떡볶이떡은 반으로 잘라 끓는 물에 데쳐 건진다.","imageUrl":null},{"step":2,"text":"꼬막은 씻어 떡을 데친 끓는 물(잔열)에 살짝 삶아 건진 후 식으면 꼬막살을 뺀다.","imageUrl":null},{"step":3,"text":"꼬치에 데친 떡과 꼬막살을 번갈아 가며 꽂는다.","imageUrl":null},{"step":4,"text":"파와 양파는 다진다.","imageUrl":null},{"step":5,"text":"고추장, 양파, 파, 다진 마늘, 조청, 간장, 고춧가루, 참기름을 넣어 고추장양념을 만든다.","imageUrl":null},{"step":6,"text":"팬에 현미유를 조금 두르고 고추장양념을 볶다가 3의 꼬막떡꼬치에 고추장양념을 입힌 후 통깨를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101958_1416273598193.jpg', 220.8, 29.7, 11.6, 5.8, 496.2),
  ('740', '물파래콩전', '반찬', '물파래 5g, 노란콩 25g(불린것 52g), 우리밀가루 10g, 현미유 5g, 홍고추 2g, 물 120g 간장 2g, 파 1g, 식초 0.5g, 통깨 0.2g', '["물파래","노란콩","우리밀가루","현미유","홍고추","물","파","식초","통깨"]'::jsonb, ARRAY['a7a59e81-de3d-4893-b56a-b2218732a25b','30b5d53c-d247-4f04-9b50-c0f728e65cf9','94786475-832c-4f97-aab7-bf6fbbe2236b','4b410642-7bf9-45ad-9055-e7d9a34edaa1','6c285c60-022a-4a00-b172-87df97f16a2f','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"물파래는 씻어 체에 걸러 물기를 제거하고 잘게 썬다.","imageUrl":null},{"step":2,"text":"물에 5시간정도 불린 노란콩은 물 반컵을 넣고 약 10분가량 삶아 건져 믹서에 곱게 간다.","imageUrl":null},{"step":3,"text":"파는 다지고 홍고추는 어슷썰기 한다.","imageUrl":null},{"step":4,"text":"밀가루에 1,2와 물 20g을 넣어 반죽을 한다.","imageUrl":null},{"step":5,"text":"팬에 현미유를 두르고 반죽을 떠서 지름 8cm 가량의 크기로 동그랗게 부치면서 윗면에 홍고추로 장식한다.","imageUrl":null},{"step":6,"text":"간장, 파, 식초, 통깨를 넣고 초간장을 만들어 물파래콩전과 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118101959_1416273599145.jpg', 181.5, 15, 10, 9.9, 124.1),
  ('400', '카스텔라케이크와 해독주스', '후식', '카스텔라 100g, 꿀 15g, 견과류 15g, 요거트 30g, 체리 10g
해독주스 : 바나나 50g, 브로콜리 25g, 사과 50g, 당근 25g, 방울토마토 25g', '["카스텔라","꿀","견과류","요거트","체리","해독주스 : 바나나","브로콜리","사과","당근","방울토마토"]'::jsonb, ARRAY['286d1783-cd34-4aae-ac8b-006529ec8bc5','bb41a88a-ea2b-4830-876d-91fe7f640296','115c21d5-f619-42df-a91e-58fccd4b2459','9bf64924-ce53-42bb-849e-7294416e95d6','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','e38c12a7-43cb-421a-a36e-7ef0d32517fa','aa597bcd-596b-4cbe-a2c4-3da0d060cb50']::uuid[], '[{"step":1,"text":"카스텔라는 반으로 잘라준 후 꿀을 발라준다.","imageUrl":null},{"step":2,"text":"견과류는 먹기 좋게 잘라준다.","imageUrl":null},{"step":3,"text":"자른 카스텔라 위에 꿀을 발라준다.","imageUrl":null},{"step":4,"text":"바른 카스텔라 위에 자른 견과류를 뿌려준다.","imageUrl":null},{"step":5,"text":"브로콜리를 뺀 해독주스 재료를 끓이다 마지막에\r\n브로콜리를 넣어 살짝 끓여준 뒤 믹서에 간다.","imageUrl":null},{"step":6,"text":"접시에 담고 요거트를 뿌리고 체리와 애플민트를\r\n올려준다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00400_2.png', 270.2, 32.8, 5.3, 13.1, 91.6),
  ('401', '토마토김치', '반찬', '방울토마토 200g, 영양부추 20g, 양파 40g, 청고추 15g, 홍고추 15g
양념 : 바나나 40g, 배 40g, 고춧가루 15g, 매실청 10g, 간편 어간장 15g
통깨 2g, 다진마늘 15g, 참기름 5g, 젓갈 5g', '["방울토마토","영양부추","양파","청고추","홍고추","양념 : 바나나","배","고춧가루","매실청","간편 어간장","통깨","다진마늘","참기름","젓갈"]'::jsonb, ARRAY['aa597bcd-596b-4cbe-a2c4-3da0d060cb50','058648c3-fd8e-476d-952f-b15dc67f1877','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','30b5d53c-d247-4f04-9b50-c0f728e65cf9','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','84104c49-0af4-4323-a56b-b67002a422d9','02fd7135-0ec3-49ec-82e3-390536ab2cf5','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','fc6e31ce-388e-45cd-956b-b238b9134eb1','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"토마토는 먹기 좋은 크기로 잘라준다.","imageUrl":null},{"step":2,"text":"청고추, 홍고추, 양파는 채 썰고 부추는 먹기\r\n좋게 잘라준다.","imageUrl":null},{"step":3,"text":"바나나, 배, 젓갈을 갈아 준 뒤 고춧가루와\r\n섞어준다.","imageUrl":null},{"step":4,"text":"만들어진 국물에 나머지 재료를 넣고 최종\r\n김치 국물을 만들어준다.","imageUrl":null},{"step":5,"text":"국물에 영양부추만 뺀 재료를 넣고 버무려준다.","imageUrl":null},{"step":6,"text":"마지막에 영양부추를 넣어 김치를 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00401_2.png', 80.2, 13.8, 3.8, 1.1, 109.5),
  ('402', '닭가슴살스튜', '반찬', '닭가슴살 200g, 당근 30g, 양파 30g, 브로콜리 30g, 감자 40g
방울토마토 100g, 우유 100g, 올리브유 15g
소스 : 토마토페이스트 100g, 다진마늘 15g, 밀가루 7g, 흰후추 3g', '["닭가슴살","당근","양파","브로콜리","감자","방울토마토","우유","올리브유","소스 : 토마토페이스트","다진마늘","밀가루","흰후추"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','9bf64924-ce53-42bb-849e-7294416e95d6','20894da1-739d-4d52-b5fe-4943bd3492d5','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','e937397f-54e2-49df-997a-f393c58360be','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','fc6e31ce-388e-45cd-956b-b238b9134eb1','aab3b0b9-d346-4697-a1c8-1b1530153788','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"닭가슴살은 먹기 좋은 크기로 잘라서 우유에\r\n재워준 뒤 뜨거운 물에 데쳐준다.","imageUrl":null},{"step":2,"text":"방울토마토는 반으로 자르고, 양파는 먹기 좋은\r\n크기로 잘라준다.","imageUrl":null},{"step":3,"text":"감자, 당근, 브로콜리는 먹기 좋은 크기로\r\n잘라 뜨거운 물에 순서대로 데쳐준다.","imageUrl":null},{"step":4,"text":"모든 재료를 올리브유에 볶아준다.","imageUrl":null},{"step":5,"text":"토마토페이스트와 닭가슴살을 데쳐낸 물을\r\n섞어 끓여준다.","imageUrl":null},{"step":6,"text":"끓고 있는 국물 50g에 밀가루를 섞어 농도를\r\n맞추어 준다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00402_2.png', 148.7, 10.6, 19.4, 3.2, 223.6),
  ('403', '가지겉절이', '반찬', '가지 250g, 양파 60g, 대파 25g, 청고추 15g, 홍고추 15g, 간편 어간장 15g
양념장 : 고추장 15g, 생강청 15g, 다진마늘 5g, 통깨 7g, 매실청 10g, 고춧가루 10g, 식초 10g', '["가지","양파","대파","청고추","홍고추","간편 어간장","양념장 : 고추장","생강청","다진마늘","통깨","매실청","고춧가루","식초"]'::jsonb, ARRAY['3e12cf79-2cde-4309-9f7c-4eccce3fde28','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','fc6e31ce-388e-45cd-956b-b238b9134eb1','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','02fd7135-0ec3-49ec-82e3-390536ab2cf5','84104c49-0af4-4323-a56b-b67002a422d9','6c285c60-022a-4a00-b172-87df97f16a2f']::uuid[], '[{"step":1,"text":"가지는 먹기 좋은 크기로 잘라서 간편 어간장에\r\n절여준다.","imageUrl":null},{"step":2,"text":"다진 대파, 청홍고추, 양파는 송송 잘라준다.","imageUrl":null},{"step":3,"text":"절여진 가지를 꼭 짜서 수분을 제거해준다.","imageUrl":null},{"step":4,"text":"양념장에 가지와 준비된 채소를 버무려 준다.","imageUrl":null},{"step":5,"text":"완성된 가지김치는 2시간 정도 후에 숙성시켜\r\n완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00403_2.png', 109.1, 16.2, 3.8, 3.2, 344.3),
  ('404', '저염 동치미', '반찬', '함초 25g, 사과 100g, 양파 25g, 무 100g, 쪽파 10g, 청고추 20g
홍고추 15g, 마늘 10g, 함초소금 2g, 찹쌀가루 15g, 매실청 30g', '["함초","사과","양파","무","쪽파","청고추","홍고추","마늘","함초소금","찹쌀가루","매실청"]'::jsonb, ARRAY['2753a03c-9508-458a-9f55-75307de4f7d5','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','f80c9a7d-1510-44e2-a82b-28b9f684e191','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','fc6e31ce-388e-45cd-956b-b238b9134eb1','2cf0c12b-f248-4012-8f53-303c730a7b3d','4cb11562-015f-4ab5-969f-0ea8483a0b42','02fd7135-0ec3-49ec-82e3-390536ab2cf5']::uuid[], '[{"step":1,"text":"함초와 쪽파는 1cm 길이로 자른다. 청고추,\r\n홍고추, 무는 한입 크기로 잘라주고 마늘은\r\n편으로 썰어준다.","imageUrl":null},{"step":2,"text":"물 1컵에 찹쌀가루를 풀어서 풀을 쑨다.","imageUrl":null},{"step":3,"text":"물 2컵에 함초, 편마늘을 넣고 국물을 만든다.","imageUrl":null},{"step":4,"text":"이 물로 무를 절여준다. 이때 무를 절였던 물을\r\n버리지 말고 찹쌀 풀과 섞어 국물을 만들어\r\n준다.","imageUrl":null},{"step":5,"text":"만들어진 국물과 찹쌀 풀을 섞어 체에 내려\r\n준다.","imageUrl":null},{"step":6,"text":"모든 재료를 한데 섞어서 저염 동치미를\r\n완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00404_2.png', 57.2, 12.2, 1.4, 0.3, 52.2),
  ('405', '장어수육구이', '반찬', '장어 250g, 양파 70g, 통생강 20g, 생강청 15g
소스 : 씨겨자 15g, 통깨 5g, 매실청 15g', '["장어","양파","통생강","생강청","소스 : 씨겨자","통깨","매실청"]'::jsonb, ARRAY['d9d44d6d-6648-409b-857c-15bf7b42f0df','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','02fd7135-0ec3-49ec-82e3-390536ab2cf5']::uuid[], '[{"step":1,"text":"장어는 생강청에 20분 정도 재워준다.","imageUrl":null},{"step":2,"text":"생강, 양파는 아주 가늘게 채 썰어서 냉수에\r\n담가 매운맛을 빼준다.","imageUrl":null},{"step":3,"text":"소스 재료로 소스를 만들어준다.","imageUrl":null},{"step":4,"text":"채 썬 양파와 생강채를 냄비에 깔고 장어를\r\n수분 없이 쪄준다.","imageUrl":null},{"step":5,"text":"쪄낸 장어는 접시에 올리고 양파, 생강채를\r\n올려 소스와 함께 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00405_2.png', 129, 3.9, 15.2, 5.9, 155.2),
  ('406', '울금해초밥', '밥', '울금가루 15g, 쌀 50g, 올리브오일 5g, 건조미역줄기 10g
맛장 : 일본된장 15g, 다진양파 15g, 두부 50g, 다진마늘 3g, 고춧가루 2g, 참기름 15g', '["울금가루","쌀","올리브오일","건조미역줄기","맛장 : 일본된장","다진양파","두부","다진마늘","고춧가루","참기름"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4566cac5-9166-4c0d-906a-bfc7360f8f5b','fc6e31ce-388e-45cd-956b-b238b9134eb1','84104c49-0af4-4323-a56b-b67002a422d9','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"쌀은 세척 후 울금물에 불려준다.","imageUrl":null},{"step":2,"text":"두부를 으깨서 수분을 빼준다.","imageUrl":null},{"step":3,"text":"쌈장을 맛장으로 만들어준다.","imageUrl":null},{"step":4,"text":"건조 미역줄기는 세척해 불린다. 이때 불리고\r\n나온 물을 이용해 밥을 한다.","imageUrl":null},{"step":5,"text":"올리브오일로 쌀을 볶아주다 미역줄기를\r\n넣고 밥을 한다.","imageUrl":null},{"step":6,"text":"두부 맛장과 함께 곁들여 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00406_2.png', 212, 44, 5, 1.8, 402.8),
  ('407', '미역줄기두부무침', '반찬', '건조미역줄기 10g, 두부 70g, 로즈마리 1g, 혼합견과류 25g
