  ('409', '주꾸미보양샐러드', '반찬', '주꾸미 50g, 사과 60g, 더덕 40g, 양파 60g, 청고추 15g, 홍고추 15g
소스 : 마늘기름 30g, 식초 15g, 다진마늘 5g, 다진대파 5g, 레몬소금 1g, 흰후추 1g
다진청고추 15g, 레몬즙 15g', '["주꾸미","사과","더덕","양파","청고추","홍고추","소스 : 마늘기름","식초","다진마늘","다진대파","레몬소금","흰후추","다진청고추","레몬즙"]'::jsonb, ARRAY['c3f77c6a-2dd2-4592-875f-0aa74771d6d0','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','641252bb-9268-421d-8b9a-314bcbc0c522','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','30b5d53c-d247-4f04-9b50-c0f728e65cf9','6c285c60-022a-4a00-b172-87df97f16a2f','fc6e31ce-388e-45cd-956b-b238b9134eb1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67']::uuid[], '[{"step":1,"text":"더덕은 손질해 어슷하게 잘라 소금물에 살짝\r\n담가준다.","imageUrl":null},{"step":2,"text":"사과는 먹기 좋게 썰어서 레몬즙에 살짝\r\n뿌려준다.","imageUrl":null},{"step":3,"text":"주꾸미는 레몬즙을 넣어 살짝 데쳐준다.","imageUrl":null},{"step":4,"text":"청고추, 홍고추는 씨를 제거하고 사과처럼\r\n잘라주고. 양파도 잘라준다.","imageUrl":null},{"step":5,"text":"소스를 만들어준다.","imageUrl":null},{"step":6,"text":"모든 채소와 주꾸미를 섞어 소스랑 한데\r\n버무려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00409_2.png', 132.7, 3.2, 20.3, 4.3, 191.8),
  ('410', '전복내장밥', '밥', '전복 100g, 칵테일새우 25g, 바지락살 25g, 당근 15g, 연근 25g, 단호박 25g
찹쌀 50g, 다진마늘 7g, 참기름 15g, 소주 15g, 흰후추 1g, 마늘기름 15g', '["전복","칵테일새우","바지락살","당근","연근","단호박","찹쌀","다진마늘","참기름","소주","흰후추","마늘기름"]'::jsonb, ARRAY['5678a9c5-5df5-4a97-8f95-77df12578956','6f10b4ad-53a2-4a07-ba89-19a6b074373d','b6047d76-6c94-4757-b1d1-9175aea0c84a','e38c12a7-43cb-421a-a36e-7ef0d32517fa','b20f623d-e722-42af-9bd1-7c11b5e15aa6','98d652af-a6d6-440c-9653-e22fc5d47d88','a5bc0b46-0192-496a-b429-d2cb90b2bca9','fc6e31ce-388e-45cd-956b-b238b9134eb1','0c0ade94-cfd8-4104-b44c-40e942cac482','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','34302eb3-407c-41e6-b9ae-89f6123f4b65']::uuid[], '[{"step":1,"text":"전복은 손질해 잘라주고 전복내장과 소주를\r\n넣어서 믹서에 간다.","imageUrl":null},{"step":2,"text":"참기름과 마늘기름을 섞어서 불린 쌀을 볶는다.","imageUrl":null},{"step":3,"text":"연근, 당근, 단호박은 작은 깍두기 모양으로\r\n잘라 각각 볶아준다.","imageUrl":null},{"step":4,"text":"전복은 작은 깍두기 모양으로 잘라서 칵테일새우,\r\n바지락살, 다진마늘, 청주를 넣어 살짝 볶아준다.","imageUrl":null},{"step":5,"text":"냄비에 갈아준 전복내장을 만들어준 기름에\r\n볶아주다 쌀을 넣고 볶고, 나머지 채소를\r\n넣어 볶는다.","imageUrl":null},{"step":6,"text":"마지막으로 새우, 바지락을 넣고 볶아 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00410_2.png', 279.8, 42.8, 12.7, 6.4, 183.8),
  ('411', '카레감자전', '반찬', '감자 150g, 유기농 밀가루 50g, 카레가루 15g, 양파 70g, 루콜라 3g, 마늘기름 30g
소스 : 발사믹식초 30g, 저염간장 15g, 설탕 15g', '["감자","유기농 밀가루","카레가루","양파","루콜라","마늘기름","소스 : 발사믹식초","저염간장","설탕"]'::jsonb, ARRAY['20894da1-739d-4d52-b5fe-4943bd3492d5','495b9f1e-aa3b-4506-9bb8-feb0a493901e','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','34302eb3-407c-41e6-b9ae-89f6123f4b65','f175019d-5a93-4cd4-aabc-e7e79445f15a','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"감자는 껍질을 벗겨서 1개를 채 썰고 물에\r\n담가둔다.","imageUrl":null},{"step":2,"text":"감자 1개는 강판에 갈아서 즙과 건지를 따로\r\n분리해준다.","imageUrl":null},{"step":3,"text":"양파를 곱게 채 썰어주고 볼에 강판에 간 건지와\r\n채 썬 감자, 채 썬 양파를 섞어 반죽을 만들어\r\n준다.","imageUrl":null},{"step":4,"text":"소스를 만들어준다.","imageUrl":null},{"step":5,"text":"팬에 한입 크기로 전을 부쳐준다.","imageUrl":null},{"step":6,"text":"루콜라를 물에 살짝 헹궈주고 전과 함께\r\n접시에 셋팅한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00411_2.png', 186.9, 29.5, 4.2, 5.8, 491.9),
  ('412', '두부채소샐러드', '반찬', '두부 100g, 건 표고버섯 10g, 치커리 15g, 홍고추 17g, 노란색 파프리카 25g, 방울토마토 40g
소스 : 요거트 50g, 겨자 2g, 꿀 15g, 레몬즙 15g', '["두부","건 표고버섯","치커리","홍고추","노란색 파프리카","방울토마토","소스 : 요거트","겨자","꿀","레몬즙"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','66458b1b-c92f-43fa-8eba-e428892ce88a','1389717e-81e4-4350-96d4-d627d851aa10','30b5d53c-d247-4f04-9b50-c0f728e65cf9','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','5b59cfae-1277-48af-99a6-833687e2da0b','286d1783-cd34-4aae-ac8b-006529ec8bc5','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67']::uuid[], '[{"step":1,"text":"두부는 먹기 좋은 크기로 잘라서 팬에 바삭\r\n하게 구워준다.","imageUrl":null},{"step":2,"text":"구워진 두부는 기름을 빼고 채 썰어준다.","imageUrl":null},{"step":3,"text":"방울토마토는 작은 사각형으로 잘라주고,\r\n치커리는 먹기좋게 잘라준다.","imageUrl":null},{"step":4,"text":"표고버섯와 홍고추, 노란파프리카는 가늘게\r\n채 썰어 볶아준다.","imageUrl":null},{"step":5,"text":"소스를 만들어준다. 잘라준 토마토는 먹기\r\n직전에 소스와 섞어준다.","imageUrl":null},{"step":6,"text":"접시에 치커리를 깔고 볶아진 두부와 채소를\r\n올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00412_2.png', 154.2, 10, 7.5, 9.4, 40.1),
  ('413', '더덕비트물김치', '반찬', '더덕 50g, 양파 60g, 청고추 15g, 홍고추 15g, 식초 10g
국물 : 비트 20g, 함초소금 5g, 생강청 30g, 식초 15g', '["더덕","양파","청고추","홍고추","식초","국물 : 비트","함초소금","생강청"]'::jsonb, ARRAY['641252bb-9268-421d-8b9a-314bcbc0c522','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','30b5d53c-d247-4f04-9b50-c0f728e65cf9','6c285c60-022a-4a00-b172-87df97f16a2f','2cf0c12b-f248-4012-8f53-303c730a7b3d','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9']::uuid[], '[{"step":1,"text":"물과 식초가 포함된 물에 담가서 쓴맛을\r\n빼준다.","imageUrl":null},{"step":2,"text":"물에 절여진 더덕은 키친타월을 이용해 물기를\r\n완전히 빼준다.","imageUrl":null},{"step":3,"text":"양파, 청고추, 홍고추도 어슷하게 썰어준다.","imageUrl":null},{"step":4,"text":"비트를 편으로 썰어서 국물을 만들어준다.","imageUrl":null},{"step":5,"text":"그릇에 더덕부터 30분 정도 담가 물을 살짝\r\n들여준다.","imageUrl":null},{"step":6,"text":"나머지 재료도 함께 담가 간을 배게 한 뒤 24\r\n시간 후부터 먹을 수가 있다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00413_2.png', 43.8, 8.9, 1.8, 0.1, 107),
  ('515', '연어허브스테이크', '반찬', '연어(150g), 로즈마리(3g), 레몬(10g), 올리브오일(30g)
, 당근(20g), 양파(20g), 토마토(30g), 마늘(10g)
버터(5g), 밀가루(10g), 토마토 소스(50g)
육수(150g), 우유(50g), 월계수잎(1장)', '["연어","로즈마리","레몬","올리브오일","당근","양파","토마토","마늘","버터","밀가루","토마토 소스","육수","우유","월계수잎"]'::jsonb, ARRAY['35db7cf0-556e-49d8-b6d2-f6e1b1e12e16','722e0bf6-fae4-4bb8-bb95-f7b407b085d7','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','fc6e31ce-388e-45cd-956b-b238b9134eb1','7aabd532-361f-4240-aa33-6bfa1be4bc4e','aab3b0b9-d346-4697-a1c8-1b1530153788','76e95535-f965-4685-a7a6-55ae26aa202c','a4c37075-c03b-47bb-8aed-5e907620f5d2','e937397f-54e2-49df-997a-f393c58360be','043a9631-bb6e-42e6-9673-4943457502fb']::uuid[], '[{"step":1,"text":"연어에 로즈마리를 위에 올려\r\n마리네이드를 한다.","imageUrl":null},{"step":2,"text":"마리네이드를 해놓은 연어에 레몬즙을\r\n뿌린다.","imageUrl":null},{"step":3,"text":"당근, 양파는 썰고 마늘과 토마토는\r\n다져 준비한다.","imageUrl":null},{"step":4,"text":"냄비에 버터를 두르고, 채소(③)를\r\n볶다가 밀가루를 넣고 볶으면서 다시\r\n토마토소스를 넣어 볶다가 육수와\r\n월계수잎을 넣어 끓인다.","imageUrl":null},{"step":5,"text":"소스가 자작 하게 끓고 있을 때, 우유를\r\n넣고 한 소끔 끓여준다.","imageUrl":null},{"step":6,"text":"팬에 올리브 오일을 두르고, 연어\r\n(①)를 올려 앞뒤로 구어 접시에\r\n담고, 토마토소스를 올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00515_2.png', 455.5, 3.5, 47.3, 28.1, 256.4),
  ('516', '해물칼국수', '일품', '밀가루(180g), 소금(0.3g), 녹말가루(20g), 덧밀가루(50g)
